        .calc-field input[type="range"]::-webkit-slider-thumb:hover {
          transform: scale(1.15) !important;
          box-shadow: 0 0 14px rgba(56, 189, 248, 0.7), 0 2px 8px rgba(0, 0, 0, 0.5) !important;
