/**
 * Simple cron scheduler using setTimeout/setInterval.
 * Supports the cron shapes used by this app: "minute hour * * *" and "minute * / 2 * * *".
 */
function scheduleJob(cronExpr, name, fn) {
  const { initialDelayMs, intervalMs } = getScheduleTiming(cronExpr);

  // Preserve the startup warmup so caches populate shortly after boot.
  setTimeout(async () => {
    try {
      await fn();
      console.info(`[CRON] ${name}: initial run complete`);
    } catch (err) {
      console.error(`[CRON] ${name}: initial run failed:`, err.message);
    }
  }, 5000);

  const runScheduled = async () => {
    try {
      await fn();
    } catch (err) {
      console.error(`[CRON] ${name} failed:`, err.message);
    }
  };

  setTimeout(() => {
    runScheduled();
    setInterval(runScheduled, intervalMs);
  }, initialDelayMs);
}

function getScheduleTiming(cronExpr, now = new Date()) {
  const [minutePart, hourPart] = cronExpr.split(' ');
  const fallback = {
    initialDelayMs: 6 * 60 * 60 * 1000,
    intervalMs: 6 * 60 * 60 * 1000,
  };
  const minute = Number(minutePart);

  if (!Number.isInteger(minute) || minute < 0 || minute > 59) {
    return fallback;
  }

  if (hourPart === '*/2') {
    const next = new Date(now);
    next.setUTCSeconds(0, 0);
    next.setUTCMinutes(minute);

    const currentHour = now.getUTCHours();
    const nextEvenHour = currentHour % 2 === 0 ? currentHour : currentHour + 1;
    next.setUTCHours(nextEvenHour);
    if (next <= now) {
      next.setUTCHours(next.getUTCHours() + 2);
    }

    return {
      initialDelayMs: next.getTime() - now.getTime(),
      intervalMs: 2 * 60 * 60 * 1000,
    };
  }

  const hour = Number(hourPart);
  if (Number.isInteger(hour) && hour >= 0 && hour <= 23) {
    const next = new Date(now);
    next.setUTCSeconds(0, 0);
    next.setUTCHours(hour, minute);
    if (next <= now) {
      next.setUTCDate(next.getUTCDate() + 1);
    }

    return {
      initialDelayMs: next.getTime() - now.getTime(),
      intervalMs: 24 * 60 * 60 * 1000,
    };
  }

  return fallback;
}

import jwt from 'jsonwebtoken';
import mongoose from 'mongoose';
import { isTokenBlacklisted } from '../config/redis.js';

/**
 * JWT verification middleware.
 * Attaches decoded token payload to req.user.
 */
export async function verifyJWT(req, res, next) {
  const authHeader = req.headers.authorization;
  if (!authHeader || !authHeader.startsWith('Bearer ')) {
    return res.status(401).json({ error: 'Access denied. No token provided.' });
  }

  const token = authHeader.split(' ')[1];
  if (!token || token === 'null' || token === 'undefined') {
    return res.status(401).json({ error: 'Access denied. Invalid token format.' });
  }

  try {
    const decoded = jwt.verify(token, process.env.JWT_SECRET, { algorithms: ['HS256'] });
    if (!decoded.userId) {
      return res.status(401).json({ error: 'Invalid token payload.' });
    }

    if (decoded.jti) {
      const blacklisted = await isTokenBlacklisted(decoded.jti);
      if (blacklisted) {
        return res.status(401).json({ error: 'Token has been revoked. Please log in again.' });
      }
    }

    req.user = decoded;
    next();
  } catch (err) {
    if (err.name === 'TokenExpiredError') {
      return res.status(401).json({ error: 'Token expired. Please log in again.' });
    }
    return res.status(401).json({ error: 'Invalid or expired token.' });
  }
}

/**
 * Validate a string as a valid MongoDB ObjectId.
 * Returns true if valid, false otherwise.
 */
export function isValidObjectId(id) {
  return mongoose.Types.ObjectId.isValid(id) && /^[0-9a-fA-F]{24}$/.test(id);
}

/**
 * Verify that a document belongs to the requesting user.
 * Used to prevent users from accessing other users' profiles, goals, etc.
 *
 * @param {Object} document - Mongoose document or lean object
 * @param {string} requestingUserId - req.user.userId
 * @returns {boolean}
 */
export function isOwner(document, requestingUserId) {
  if (!document || !requestingUserId) return false;
  const docUserId = document.userId?.toString?.() || document.userId;
  return docUserId === requestingUserId.toString();
}

/**
 * WealthGenie Global Error Handler
 * Provides structured error logging and safe client responses.
 * Never exposes internal error messages or stack traces to clients.
 */

import crypto from 'crypto';
import logger from '../utils/logger.js';

const ERROR_CATEGORIES = {
  VALIDATION: 'VALIDATION_ERROR',
  AUTH: 'AUTH_ERROR',
  NOT_FOUND: 'NOT_FOUND_ERROR',
  CONFLICT: 'CONFLICT_ERROR',
  ML_SERVICE: 'ML_SERVICE_ERROR',
  GEMINI: 'GEMINI_API_ERROR',
  MARKET_DATA: 'MARKET_DATA_ERROR',
  DATABASE: 'DATABASE_ERROR',
  RATE_LIMIT: 'RATE_LIMIT_ERROR',
  UNKNOWN: 'UNKNOWN_ERROR',
};

function categoriseError(err) {
  if (err.name === 'ValidationError' || err.isJoi) return ERROR_CATEGORIES.VALIDATION;
  if (err.type === 'entity.parse.failed' || (err instanceof SyntaxError && err.status === 400)) {
    return ERROR_CATEGORIES.VALIDATION;
  }
  if (err.name === 'JsonWebTokenError' || err.name === 'TokenExpiredError')
    return ERROR_CATEGORIES.AUTH;
  if (err.name === 'CastError' && err.kind === 'ObjectId')
    return ERROR_CATEGORIES.VALIDATION;
  if (err.message?.includes('ML service') || err.message?.includes('SHAP'))
    return ERROR_CATEGORIES.ML_SERVICE;
  if (err.message?.includes('Gemini') || err.message?.includes('generativelanguage'))
    return ERROR_CATEGORIES.GEMINI;
  if (err.message?.includes('AMFI') || err.message?.includes('Yahoo') || err.message?.includes('market'))
    return ERROR_CATEGORIES.MARKET_DATA;
  if (err.name === 'MongoServerError' && err.code === 11000)
    return ERROR_CATEGORIES.CONFLICT;
  if (err.name?.startsWith('Mongo') || err.name?.startsWith('Mongoose') || err.message?.includes('buffering timed out'))
    return ERROR_CATEGORIES.DATABASE;
  return ERROR_CATEGORIES.UNKNOWN;
}

const CLIENT_MESSAGES = {
  [ERROR_CATEGORIES.VALIDATION]: 'Invalid request data.',
  [ERROR_CATEGORIES.AUTH]: 'Authentication failed.',
  [ERROR_CATEGORIES.NOT_FOUND]: 'The requested resource was not found.',
  [ERROR_CATEGORIES.CONFLICT]: 'A resource with this data already exists.',
  [ERROR_CATEGORIES.ML_SERVICE]: 'Recommendation engine temporarily unavailable.',
  [ERROR_CATEGORIES.GEMINI]: 'AI advisory service temporarily unavailable.',
  [ERROR_CATEGORIES.MARKET_DATA]: 'Live market data temporarily unavailable.',
  [ERROR_CATEGORIES.DATABASE]: 'Database operation failed.',
  [ERROR_CATEGORIES.RATE_LIMIT]: 'Too many requests. Please try again later.',
  [ERROR_CATEGORIES.UNKNOWN]: 'An unexpected error occurred.',
};

/**
 * Generate a request fingerprint for audit trails.
 * Hashes IP + User-Agent to create a pseudonymous identifier
 * for correlating suspicious activity without storing PII.
 */
function getRequestFingerprint(req) {
  const ip = req.ip || req.connection?.remoteAddress || 'unknown';
  const ua = req.headers['user-agent'] || 'unknown';
  try {
    return crypto.createHash('sha256').update(`${ip}:${ua}`).digest('hex').substring(0, 12);
  } catch {
    return 'no-fingerprint';
  }
}

import mongoose from 'mongoose';

export function errorHandler(err, req, res, _next) {
  const category = categoriseError(err);
  let rawStatus = Number(err.status || err.statusCode);
  let status = Number.isInteger(rawStatus) && rawStatus >= 400 && rawStatus <= 599
    ? rawStatus
    : 500;

  // Enhance database error categorization for connection/network loss to return 503
  if (category === ERROR_CATEGORIES.DATABASE) {
    const isConnectionError = 
      err.name === 'MongoNetworkError' ||
      err.name === 'MongoTimeoutError' ||
      err.message?.includes('connection') ||
      err.message?.includes('topology') ||
      err.message?.includes('replica set') ||
      err.message?.includes('pool') ||
      err.message?.includes('buffering timed out') ||
      mongoose.connection.readyState !== 1;
    if (isConnectionError) {
      status = 503;
      err.clientMessage = 'Database service temporarily unavailable.';
    }
  }

  // Response time tracking (if start time was recorded)
  const responseTimeMs = req._startTime
    ? Date.now() - req._startTime
    : null;

  // Structured JSON log — easy to grep in production
  const logEntry = {
    timestamp: new Date().toISOString(),
    category,
    status,
    method: req.method,
    path: req.originalUrl || req.path,
    userId: req.user?.userId || 'anonymous',
    requestId: req.headers['x-request-id'] || null,
    responseTimeMs,
    message: err.message,
  };

  // Security-specific logging for auth failures
  if (category === ERROR_CATEGORIES.AUTH || status === 401 || status === 403) {
    logEntry.securityEvent = true;
    logEntry.ip = req.ip || req.connection?.remoteAddress || 'unknown';
    logEntry.userAgent = (req.headers['user-agent'] || 'unknown').substring(0, 100);
    logger.warn('Auth failure security event', {
      method: req.method,
      path: req.originalUrl,
      ip: logEntry.ip,
      userAgent: logEntry.userAgent,
    });
  }

  // Only include stack traces in development
  if (process.env.NODE_ENV === 'development') {
    logEntry.stack = err.stack;
  }

  if (status >= 500) {
    logger.error('Server error handled', { logEntry, err });
  } else {
    logger.warn('Client request warning handled', { logEntry });
  }

  // Prevent double-sending if headers already sent
  if (res.headersSent) return;

  // Safe client response — never expose internals
  return res.status(status).json({
    error: err.clientMessage || CLIENT_MESSAGES[category],
    request_id: req.headers['x-request-id'] || null,
  });
}

/**
 * Async route wrapper — catches rejected promises and forwards to error handler.
 * Use this instead of try/catch in every route.
 *
 * @param {Function} fn - Async route handler (req, res, next) => Promise
 * @returns {Function} Express middleware
 */
export function asyncHandler(fn) {
  return (req, res, next) => {
    Promise.resolve(fn(req, res, next)).catch(next);
  };
}

/**
 * Create an operational error with a specific status code and client message.
 *
 * @param {number} status - HTTP status code
 * @param {string} message - Internal message for logging
 * @param {string} [clientMessage] - Safe message for the client
 * @returns {Error}
 */
export function createError(status, message, clientMessage) {
  const err = new Error(message);
  err.status = status;
  if (clientMessage) err.clientMessage = clientMessage;
  return err;
}

// Catch unhandled promise rejections — prevents silent failures
process.on('unhandledRejection', (reason) => {
  console.error(JSON.stringify({
    timestamp: new Date().toISOString(),
    category: 'UNHANDLED_REJECTION',
    message: String(reason),
    stack: reason?.stack,
  }));
});

// Catch uncaught exceptions — log and terminate immediately so process managers can restart
process.on('uncaughtException', (err) => {
  console.error(JSON.stringify({
    timestamp: new Date().toISOString(),
    category: 'UNCAUGHT_EXCEPTION',
    message: err.message,
    stack: err.stack,
  }));
  process.exit(1);
});

import { Router } from 'express';
import mongoose from 'mongoose';
import { verifyJWT, isOwner, isValidObjectId } from '../middleware/authMiddleware.js';
import { asyncHandler, createError } from '../middleware/errorHandler.js';
import { validate, goalSchema, goalUpdateSchema } from '../validation/schemas.js';
import Goal from '../models/Goal.js';
import FinancialProfile from '../models/FinancialProfile.js';
import Recommendation from '../models/Recommendation.js';
import { reverseSIP, runMonteCarloWithGoal, getInstrumentVolatility } from '../services/monteCarloEngine.js';
import { getGoalAdvisory } from '../services/geminiService.js';
import { idempotency } from '../middleware/idempotency.js';

const router = Router();

/**
 * Detect stale/error advice that should be regenerated.
 */
const STALE_ADVICE_PATTERNS = [
  'temporarily unavailable',
  'could not process',
  'api key not configured',
];

function isStaleAdvice(advice) {
  if (!advice || typeof advice !== 'string' || advice.trim().length === 0) return true;
  const normalisedAdvice = advice.toLowerCase();
  return STALE_ADVICE_PATTERNS.some(p => normalisedAdvice.includes(p));
}

async function findOwnedProfileById(profileId, userId) {
  const id = profileId?.toString?.() || profileId;
  if (!id || !isValidObjectId(id)) return null;
  return FinancialProfile.findOne({ _id: id, userId }).lean();
}

/**
 * Generate AI advice for a goal. Handles errors gracefully with a fallback.
 */
async function generateGoalAdvice(goal, profile, userMonthlySavings) {
  const now = new Date();
  const yearsRemaining = Math.max(1, Math.round(
    (new Date(goal.target_date) - now) / (365.25 * 24 * 60 * 60 * 1000)
  ));

  const profileContext = {
    age: profile?.age || 30,
    annualIncome: profile?.annualIncome || 600000,
    riskCategory: profile?.riskCategory || 'Moderate',
  };

  const prompt = `User is ${goal.status.replace(/_/g, ' ')} for goal "${goal.goal_name}" `
    + `worth ₹${goal.target_amount.toLocaleString('en-IN')} in ${yearsRemaining} years. `
    + `Required SIP: ₹${(goal.recommended_sip || 0).toLocaleString('en-IN')}/month. `
    + `Their current savings capacity: ₹${(userMonthlySavings || 10000).toLocaleString('en-IN')}/month. `
    + `Suggest one specific actionable financial adjustment in 2 sentences.`;

  try {
    const advice = await getGoalAdvisory(prompt, profileContext);
    return advice;
  } catch (_) {
    const instrument = (goal.recommended_instrument || 'Equity MF').replace(/_/g, ' ');
    return `To stay on track for your "${goal.goal_name}" goal, maintain a monthly SIP of `
      + `₹${(goal.recommended_sip || 5000).toLocaleString('en-IN')} in ${instrument}.`;
  }
}

/**
 * POST /api/goals/create [Protected]
 * Create a new financial goal with automated SIP computation and Monte Carlo analysis.
 */
router.post('/create', verifyJWT, idempotency(), validate(goalSchema), asyncHandler(async (req, res) => {
  const { goal_name, target_amount, target_date, current_savings, profileId, priority } = req.body;

  // Validate profileId ownership if provided
  let profile = null;
  if (profileId) {
    if (!isValidObjectId(profileId)) {
      throw createError(400, 'Invalid profileId in goal create', 'Invalid profile ID.');
    }
    profile = await FinancialProfile.findById(profileId).lean();
    if (!profile) {
      throw createError(404, `Profile not found for goal create: ${profileId}`, 'Profile not found.');
    }
    if (!isOwner(profile, req.user.userId)) {
      throw createError(403, `Unauthorized goal-profile access: ${profileId}`, 'Access denied.');
    }
  }

  // Fall back to latest profile
  if (!profile) {
    profile = await FinancialProfile.findOne({ userId: req.user.userId })
      .sort({ createdAt: -1 }).lean();
  }

  // Calculate years remaining with invariant checks
  const targetDateObj = new Date(target_date);
  const now = new Date();

  // Invariant: target_date must be at least 6 months in the future
  const sixMonthsFromNow = new Date();
  sixMonthsFromNow.setMonth(sixMonthsFromNow.getMonth() + 6);
  if (targetDateObj < sixMonthsFromNow) {
    throw createError(400,
      `Goal target_date too close: ${target_date} (minimum: ${sixMonthsFromNow.toISOString()})`,
      'Target date must be at least 6 months from today for meaningful projections.'
    );
  }

  // Duplicate goal name check - prevent data confusion
  const existingGoal = await Goal.findOne({
    userId: req.user.userId,
    goal_name: { $regex: new RegExp(`^${goal_name.replace(/[.*+?^${}()|[\]\\]/g, '\\$&')}$`, 'i') },
  }).lean();
  if (existingGoal) {
    throw createError(409,
      `Duplicate goal name: "${goal_name}" for user ${req.user.userId}`,
      `A goal named "${goal_name}" already exists. Use a different name.`
    );
  }

  const msRemaining = targetDateObj - now;
  const rawYears = msRemaining / (365.25 * 24 * 60 * 60 * 1000);
  const yearsRemaining = Math.max(0.5, Math.floor(rawYears * 4) / 4);

  // Guard: if yearsRemaining is somehow NaN (invalid date), reject
  if (!Number.isFinite(yearsRemaining)) {
    throw createError(400, `Invalid target_date produced NaN years: ${target_date}`, 'Invalid target date.');
  }

  // Find the user's latest recommendation
  let latestRec = null;
  if (profile?._id) {
    latestRec = await Recommendation.findOne({ userId: req.user.userId, profileId: profile._id })
      .sort({ generatedAt: -1 }).lean();
  }
  if (!latestRec) {
    latestRec = await Recommendation.findOne({ userId: req.user.userId })
      .sort({ generatedAt: -1 }).lean();
  }
  const recommendedInstrument = latestRec?.instruments?.[0]?.type || 'Equity_MF';

  // Get volatility params for the recommended instrument
  const vol = getInstrumentVolatility(recommendedInstrument);

  // Compute post-tax adjusted rate if profile is available
  let postTaxRate = vol.mean;
  if (profile) {
    try {
      const { calculatePostTaxReturn } = await import('../services/postTaxCalculator.js');
      const ptResult = calculatePostTaxReturn(
        recommendedInstrument, vol.mean,
        profile.annualIncome || (profile.income * 12),
        yearsRemaining, profile.taxRegime || 'new'
      );
      postTaxRate = ptResult.postTaxReturn;
    } catch (_) {
      // Fallback to pre-tax if post-tax calc fails
    }
  }

  // Compute inflation-adjusted target amount (default inflation: 5%)
  const inflationRate = 0.05;
  const inflationAdjustedTarget = Math.round(target_amount * Math.pow(1 + inflationRate, yearsRemaining));

  // Compute required monthly SIP using reverse formula with POST-TAX rate against inflation-adjusted target
  const rawSIP = reverseSIP(inflationAdjustedTarget, postTaxRate, yearsRemaining, current_savings || 0);
  const requiredSIP = Math.max(500, Math.round(Number.isFinite(rawSIP) ? rawSIP : 5000));

  // Run Monte Carlo with the required SIP and POST-TAX rate against inflation-adjusted target
  const mcResult = runMonteCarloWithGoal({
    monthlyInvestment: requiredSIP,
    postTaxAnnualReturn: postTaxRate,
    annualVolatility: vol.stdDev,
    years: yearsRemaining,
    simulations: 5000,
    targetAmount: inflationAdjustedTarget,
    currentSavings: current_savings || 0,
  });

  // Self-check invariants on Monte Carlo output
  if (mcResult.goal_probability !== null) {
    if (!Number.isFinite(mcResult.goal_probability) || mcResult.goal_probability < 0 || mcResult.goal_probability > 1) {
      console.error(`[Goals INVARIANT] goal_probability out of bounds: ${mcResult.goal_probability}. Clamping.`);
      mcResult.goal_probability = Math.max(0, Math.min(1, mcResult.goal_probability || 0));
    }
  }
  const lastIdx = mcResult.p50.length - 1;
  if (lastIdx >= 0 && mcResult.p10[lastIdx] > mcResult.p90[lastIdx]) {
    console.error('[Goals INVARIANT] p10 > p90 - Monte Carlo band inversion detected.');
  }

  // Determine status using PROBABILITY-BASED classification
  const userMonthlySavings = profile?.savings || 10000;
  const gap = requiredSIP - userMonthlySavings;

  let status;
  const prob = mcResult.goal_probability;
  if (prob !== null && prob !== undefined) {
    if (prob >= 0.65) status = 'on_track';
    else if (prob >= 0.35) status = 'at_risk';
    else status = 'off_track';
  } else {
    if (gap <= 0) status = 'on_track';
    else if (gap <= userMonthlySavings * 0.25) status = 'at_risk';
    else status = 'off_track';
  }

  // Generate Gemini advice for this goal
  const goalForAdvice = {
    goal_name,
    target_amount,
    target_date: targetDateObj,
    recommended_sip: requiredSIP,
    recommended_instrument: recommendedInstrument,
    status,
  };
  const geminiAdvice = await generateGoalAdvice(goalForAdvice, profile, userMonthlySavings);

  // Build Recharts chart data
  const chartData = mcResult.years_array.map((yr, i) => ({
    year: yr,
    p10: mcResult.p10[i],
    p25: mcResult.p25[i],
    p50: mcResult.p50[i],
    p75: mcResult.p75[i],
    p90: mcResult.p90[i],
  }));

  // Mongoose transaction wrapper for multi-document writes (Goal + FinancialProfile).
  // Gracefully degrades to sequential writes if MongoDB doesn't support transactions
  // (standalone mode without replica set).
  const goalData = {
    userId: req.user.userId,
    profileId: profile?._id,
    goal_name,
    target_amount,
    inflation_adjusted_target: inflationAdjustedTarget,
    target_date: targetDateObj,
    current_savings: current_savings || 0,
    recommended_sip: requiredSIP,
    recommended_instrument: recommendedInstrument,
    probability_of_success: mcResult.goal_probability,
    gap_amount: Math.max(0, gap),
    status,
    priority: priority || 'Medium',
    monte_carlo_summary: {
      p10: mcResult.p10[lastIdx],
      p25: mcResult.p25[lastIdx],
      p50: mcResult.p50[lastIdx],
      p75: mcResult.p75[lastIdx],
      p90: mcResult.p90[lastIdx],
      simulations_run: mcResult.simulations_run,
    },
    chart_data: chartData,
    mc_computed_at: new Date(),
    years_remaining: yearsRemaining,
    gemini_advice: geminiAdvice,
  };

  let goal = null;
  let usedTransaction = false;

  try {
  try {
    // Attempt transactional write
    const session = await mongoose.startSession();
    try {
      session.startTransaction();

      const goals = await Goal.create([goalData], { session });
      goal = goals[0];

      if (profile?._id) {
        await FinancialProfile.updateOne(
          { _id: profile._id },
          { $set: { lastGoalCreatedAt: new Date() } },
          { session }
        );
      }

      await session.commitTransaction();
      usedTransaction = true;
    } catch (txErr) {
      try { await session.abortTransaction(); } catch (_) { /* already aborted */ }

      // If transactions aren't supported (standalone MongoDB), fall back
      const msg = txErr.message || '';
      if (msg.includes('Transaction numbers are only allowed on a replica set') ||
          msg.includes('transaction') && msg.includes('not supported')) {
        console.warn('[Goals] Transactions not supported — falling back to sequential writes.');
        goal = null; // reset, will create below
      } else {
        throw txErr; // real error, propagate
      }
    } finally {
      session.endSession();
    }
  } catch (sessionErr) {
    // startSession itself can fail on very old drivers — fall back
    const msg = sessionErr.message || '';
    if (!msg.includes('replica set') && !msg.includes('not supported') && !msg.includes('session')) {
      throw sessionErr;
    }
    console.warn('[Goals] Session not available — falling back to sequential writes.');
  }

  // Fallback: sequential writes (no atomicity guarantee, but functional)
  if (!goal) {
    goal = await Goal.create(goalData);
    if (profile?._id) {
      await FinancialProfile.updateOne(
        { _id: profile._id },
        { $set: { lastGoalCreatedAt: new Date() } }
      );
    }
  }
  } catch (createErr) {
    // Handle race condition: two concurrent requests both passed the findOne
    // duplicate check, but the unique compound index on {userId, goal_name}
    // rejected the second insert with a duplicate key error.
    if (createErr.code === 11000) {
      throw createError(409,
        `Concurrent duplicate goal name: "${goal_name}" for user ${req.user.userId}`,
        `A goal named "${goal_name}" already exists. Use a different name.`
      );
    }
    throw createErr;
  }

  res.status(201).json({
    goalId: goal._id,
    ...goal.toObject(),
    chartData,
    years_remaining: yearsRemaining,
  });
}));

/**
 * GET /api/goals [Protected]
 * List all goals for the current user.
 * Automatically regenerates AI advice if it contains stale/error text.
 */
router.get('/', verifyJWT, asyncHandler(async (req, res) => {
  const goals = await Goal.find({ userId: req.user.userId }).sort({ target_date: 1 });

  const staleGoals = goals.filter(g => isStaleAdvice(g.gemini_advice));

  if (staleGoals.length > 0) {
    // Regenerate advice with a timeout - don't block the response for too long
    const regenerationPromises = staleGoals.map(async (g) => {
      try {
        const profile = await findOwnedProfileById(g.profileId, req.user.userId);
        const userMonthlySavings = profile?.savings || 10000;
        const newAdvice = await generateGoalAdvice(g, profile, userMonthlySavings);

        if (!isStaleAdvice(newAdvice)) {
          await Goal.findByIdAndUpdate(g._id, { gemini_advice: newAdvice });
        }
      } catch (e) {
        console.warn('[Goals] Advice regeneration failed for', g.goal_name, ':', e.message);
      }
    });

    // Wait up to 8 seconds for regeneration, then respond with whatever we have
    let regenerationTimerId;
    const timeoutPromise = new Promise(resolve => {
      regenerationTimerId = setTimeout(resolve, 8000);
    });
    await Promise.race([
      Promise.allSettled(regenerationPromises),
      timeoutPromise,
    ]);
    clearTimeout(regenerationTimerId);
  }

  // Refetch goals to ensure fresh advice is included, and compute dynamic chartData for all goals
  const freshGoals = await Goal.find({ userId: req.user.userId }).sort({ target_date: 1 });
  
  const goalsArr = await Promise.all(freshGoals.map(async (g) => {
    const targetDateObj = new Date(g.target_date);
    const now = new Date();
    const msRemaining = targetDateObj - now;
    const rawYears = msRemaining / (365.25 * 24 * 60 * 60 * 1000);
    const yearsRemaining = Math.max(0.5, Math.floor(rawYears * 4) / 4);
    
    let chartData;
    const isCacheValid = g.chart_data && 
                         g.chart_data.length > 0 && 
                         g.mc_computed_at && 
                         g.years_remaining === yearsRemaining && 
                         (Date.now() - new Date(g.mc_computed_at).getTime()) < 24 * 60 * 60 * 1000;

    if (isCacheValid) {
      // Use cached chartData from Goal model
      chartData = g.chart_data.map(item => ({
        year: item.year,
        p10: item.p10,
        p25: item.p25,
        p50: item.p50,
        p75: item.p75,
        p90: item.p90,
      }));
    } else {
      // Cache is stale or missing - run Monte Carlo and update DB
      const vol = getInstrumentVolatility(g.recommended_instrument || 'Equity_MF');
      
      let postTaxRate = vol.mean;
      const profile = await findOwnedProfileById(g.profileId, req.user.userId);
      if (profile) {
        try {
          const { calculatePostTaxReturn } = await import('../services/postTaxCalculator.js');
          const ptResult = calculatePostTaxReturn(
            g.recommended_instrument || 'Equity_MF', vol.mean,
            profile.annualIncome || (profile.income * 12),
            yearsRemaining, profile.taxRegime || 'new'
          );
          postTaxRate = ptResult.postTaxReturn;
        } catch (err) {
          console.warn('[Goals] Failed to calculate post-tax return during Monte Carlo:', err.message);
        }
      }
      
      const targetAmt = g.inflation_adjusted_target || g.target_amount;
      const mcResult = runMonteCarloWithGoal({
        monthlyInvestment: g.recommended_sip || 5000,
        postTaxAnnualReturn: postTaxRate,
        annualVolatility: vol.stdDev,
        years: yearsRemaining,
        simulations: 2000,
        targetAmount: targetAmt,
        currentSavings: g.current_savings || 0,
      });

      chartData = mcResult.years_array.map((yr, i) => ({
        year: yr,
        p10: mcResult.p10[i],
        p25: mcResult.p25[i],
        p50: mcResult.p50[i],
        p75: mcResult.p75[i],
        p90: mcResult.p90[i],
      }));

      // Cache it back to database asynchronously (don't block the request)
      Goal.findByIdAndUpdate(g._id, {
        chart_data: chartData,
        mc_computed_at: new Date(),
        years_remaining: yearsRemaining,
        probability_of_success: mcResult.goal_probability,
        monte_carlo_summary: {
          p10: mcResult.p10[mcResult.p10.length - 1],
          p25: mcResult.p25[mcResult.p25.length - 1],
          p50: mcResult.p50[mcResult.p50.length - 1],
          p75: mcResult.p75[mcResult.p75.length - 1],
          p90: mcResult.p90[mcResult.p90.length - 1],
          simulations_run: mcResult.simulations_run,
        }
      }).catch(err => console.error('[Goals Cache] Failed to write cache to DB:', err.message));
    }

    return {
      ...g.toObject(),
      chartData,
      years_remaining: yearsRemaining,
    };
  }));

  res.json({ goals: goalsArr });
}));

/**
 * PATCH /api/goals/:goalId/refresh-advice [Protected]
 * Manually refresh AI advice for a specific goal.
 */
router.patch('/:goalId/refresh-advice', verifyJWT, asyncHandler(async (req, res) => {
  const { goalId } = req.params;

  if (!isValidObjectId(goalId)) {
    throw createError(400, 'Invalid goalId', 'Invalid goal ID.');
  }

  const goal = await Goal.findOne({ _id: goalId, userId: req.user.userId });
  if (!goal) {
    throw createError(404, `Goal not found: ${goalId}`, 'Goal not found.');
  }

  const profile = await findOwnedProfileById(goal.profileId, req.user.userId);
  const userMonthlySavings = profile?.savings || 10000;
  const newAdvice = await generateGoalAdvice(goal, profile, userMonthlySavings);

  goal.gemini_advice = newAdvice;
  await goal.save();

  res.json({ goalId: goal._id, gemini_advice: newAdvice });
}));

/**
 * PATCH /api/goals/:goalId [Protected]
 * Update a goal's priority, savings, or target, and recompute Monte Carlo fields.
 */
router.patch('/:goalId', verifyJWT, validate(goalUpdateSchema), asyncHandler(async (req, res) => {
  const { goalId } = req.params;
  const { priority, current_savings, target_amount } = req.body;

  if (!isValidObjectId(goalId)) {
    throw createError(400, 'Invalid goalId', 'Invalid goal ID.');
  }

  const goal = await Goal.findOne({ _id: goalId, userId: req.user.userId });
  if (!goal) {
    throw createError(404, `Goal not found: ${goalId}`, 'Goal not found.');
  }

  if (priority !== undefined) goal.priority = priority;
  if (current_savings !== undefined) goal.current_savings = Number(current_savings);
  if (target_amount !== undefined) goal.target_amount = Number(target_amount);

  if (current_savings !== undefined || target_amount !== undefined) {
    const profile = await findOwnedProfileById(goal.profileId, req.user.userId) ||
                    await FinancialProfile.findOne({ userId: req.user.userId }).sort({ createdAt: -1 }).lean();
    
    const targetDateObj = new Date(goal.target_date);
    const now = new Date();
    const msRemaining = targetDateObj - now;
    const rawYears = msRemaining / (365.25 * 24 * 60 * 60 * 1000);
    const yearsRemaining = Math.max(0.5, Math.floor(rawYears * 4) / 4);

    const vol = getInstrumentVolatility(goal.recommended_instrument || 'Equity_MF');
    let postTaxRate = vol.mean;
    if (profile) {
      try {
        const { calculatePostTaxReturn } = await import('../services/postTaxCalculator.js');
        const ptResult = calculatePostTaxReturn(
          goal.recommended_instrument || 'Equity_MF', vol.mean,
          profile.annualIncome || (profile.income * 12),
          yearsRemaining, profile.taxRegime || 'new'
        );
        postTaxRate = ptResult.postTaxReturn;
      } catch (err) {
        console.warn('[Goals] Failed to calculate post-tax return during goal initialization:', err.message);
      }
    }

    const inflationRate = 0.05;
    const inflationAdjustedTarget = Math.round(goal.target_amount * Math.pow(1 + inflationRate, yearsRemaining));
    goal.inflation_adjusted_target = inflationAdjustedTarget;

    const rawSIP = reverseSIP(inflationAdjustedTarget, postTaxRate, yearsRemaining, goal.current_savings);
    goal.recommended_sip = Math.max(500, Math.round(Number.isFinite(rawSIP) ? rawSIP : 5000));

    const mcResult = runMonteCarloWithGoal({
      monthlyInvestment: goal.recommended_sip,
      postTaxAnnualReturn: postTaxRate,
      annualVolatility: vol.stdDev,
      years: yearsRemaining,
      simulations: 2000,
      targetAmount: inflationAdjustedTarget,
      currentSavings: goal.current_savings || 0,
    });

    goal.probability_of_success = mcResult.goal_probability;
    goal.gap_amount = Math.max(0, goal.recommended_sip - (profile?.savings || 10000));
    
    const lastIdx = mcResult.p50.length - 1;
    goal.monte_carlo_summary = {
      p10: mcResult.p10[lastIdx],
      p25: mcResult.p25[lastIdx],
      p50: mcResult.p50[lastIdx],
      p75: mcResult.p75[lastIdx],
      p90: mcResult.p90[lastIdx],
      simulations_run: mcResult.simulations_run,
    };

    // Cache chart data
    const chartData = mcResult.years_array.map((yr, i) => ({
      year: yr,
      p10: mcResult.p10[i],
      p25: mcResult.p25[i],
      p50: mcResult.p50[i],
      p75: mcResult.p75[i],
      p90: mcResult.p90[i],
    }));
    goal.chart_data = chartData;
    goal.mc_computed_at = new Date();
    goal.years_remaining = yearsRemaining;

    if (mcResult.goal_probability >= 0.65) goal.status = 'on_track';
    else if (mcResult.goal_probability >= 0.35) goal.status = 'at_risk';
    else goal.status = 'off_track';

    goal.gemini_advice = await generateGoalAdvice(goal, profile, profile?.savings || 10000);
  }

  await goal.save();
  res.json({ success: true, goal });
}));

/**
 * DELETE /api/goals/:goalId [Protected]
 * Delete a financial goal.
 */
router.delete('/:goalId', verifyJWT, asyncHandler(async (req, res) => {
  const { goalId } = req.params;

  if (!isValidObjectId(goalId)) {
    throw createError(400, 'Invalid goalId', 'Invalid goal ID.');
  }

  const goal = await Goal.findOneAndDelete({ _id: goalId, userId: req.user.userId });
  if (!goal) {
    throw createError(404, `Goal not found for delete: ${goalId}`, 'Goal not found.');
  }

  res.json({ deleted: true, goalId });
}));

export default router;

import { Router } from 'express';
import mongoose from 'mongoose';
import { redisClient, redisAvailable } from '../config/redis.js';
import { checkMLHealth } from '../services/mlClient.js';

const router = Router();

/**
 * GET /health/deep
 * Performs a deep health check of Database, Redis, and ML microservice.
 * Returns 200 OK if all UP, or 503 Service Unavailable if any dependency is DOWN.
 */
router.get('/deep', async (req, res) => {
  const health = {
    status: 'UP',
    timestamp: new Date().toISOString(),
    correlationId: req.correlationId || null,
    services: {
      database: 'DOWN',
      redis: 'DOWN',
      ml: 'DOWN',
    }
  };

  // 1. Check MongoDB
  try {
    const isDbConnected = mongoose.connection.readyState === 1;
    if (isDbConnected) {
      // Run quick admin ping to confirm actual network/liveness
      await mongoose.connection.db.admin().ping();
      health.services.database = 'UP';
    }
  } catch (err) {
    console.error('[Health Check] Database health check failed:', err.message);
  }

  // 2. Check Redis
  try {
    if (redisAvailable && redisClient) {
      const pingRes = await redisClient.ping();
      if (pingRes === 'PONG') {
        health.services.redis = 'UP';
      }
    }
  } catch (err) {
    console.error('[Health Check] Redis health check failed:', err.message);
  }

  // 3. Check ML Microservice
  try {
    const mlHealth = await checkMLHealth(req.correlationId);
    if (mlHealth && (mlHealth.status === 'UP' || mlHealth.status === 'healthy' || mlHealth.healthy === true)) {
      health.services.ml = 'UP';
    }
  } catch (err) {
    console.error('[Health Check] ML service health check failed:', err.message);
  }

  // Determine overall status
  const allServicesUp = Object.values(health.services).every(status => status === 'UP');
  if (allServicesUp) {
    res.status(200).json(health);
  } else {
    health.status = 'DOWN';
    res.status(503).json(health);
  }
});

/**
 * GET /health
 * Simple liveness probe for load balancer.
 */
router.get('/', (req, res) => {
  res.status(200).json({ status: 'UP', timestamp: new Date().toISOString() });
});

/**
 * GET /health/ready
 * Readiness probe — returns 200 only when the database is connected and responsive.
 * Container orchestrators use this to decide when to route traffic.
 */
router.get('/ready', async (req, res) => {
  try {
    if (mongoose.connection.readyState !== 1) {
      return res.status(503).json({ status: 'NOT_READY', reason: 'Database not connected' });
    }
    await mongoose.connection.db.admin().ping();
    res.status(200).json({ status: 'READY', timestamp: new Date().toISOString() });
  } catch (err) {
    res.status(503).json({ status: 'NOT_READY', reason: err.message });
  }
});

/**
 * GET /health/live
 * Liveness probe — returns 200 if the process is alive.
 * Container orchestrators use this to decide whether to restart the container.
 */
router.get('/live', (req, res) => {
  res.status(200).json({
    status: 'ALIVE',
    uptime_seconds: Math.round(process.uptime()),
    timestamp: new Date().toISOString(),
  });
});

export default router;

import { Router } from 'express';
import { asyncHandler } from '../middleware/errorHandler.js';
import Instrument from '../models/Instrument.js';
import { getCache, setCache } from '../config/redis.js';

const router = Router();

// Allowed sort fields to prevent injection via sort parameter
const ALLOWED_SORT_FIELDS = new Set(['name', 'interestRate', 'returns1yr', 'returns3yr', 'returns5yr', 'riskLevel', 'aumCr', 'expenseRatio']);
const ALLOWED_TYPES = new Set(['FD', 'Mutual_Fund', 'ETF', 'Government', 'ELSS']);

/**
 * GET /api/instruments [Public]
 * List instruments with filtering, sorting, and pagination.
 */
router.get('/', asyncHandler(async (req, res) => {
  const { type, sort, order, limit, page } = req.query;

  // Validate type if provided
  if (type && !ALLOWED_TYPES.has(type)) {
    return res.status(400).json({ error: `Invalid instrument type. Allowed: ${[...ALLOWED_TYPES].join(', ')}` });
  }

  const cacheKey = `instruments:${type || 'all'}:${sort || 'name'}:${order || 'asc'}:${page || 1}:${limit || 20}`;

  // Check Redis cache
  const cached = await getCache(cacheKey);
  if (cached) return res.json({ ...cached, fromCache: true });

  // Build query
  const query = {};
  if (type) query.type = type;

  // Validate sort field to prevent NoSQL injection
  const sortField = (sort === 'rate' ? 'interestRate' : sort) || 'name';
  const safeSortField = ALLOWED_SORT_FIELDS.has(sortField) ? sortField : 'name';
  const sortOrder = order === 'desc' ? -1 : 1;

  // Pagination with bounds
  const pageSize = Math.min(Math.max(parseInt(limit) || 20, 1), 100);
  const pageNum = Math.max(parseInt(page) || 1, 1);
  const skip = (pageNum - 1) * pageSize;

  const [instruments, total] = await Promise.all([
    Instrument.find(query).sort({ [safeSortField]: sortOrder }).skip(skip).limit(pageSize).lean(),
    Instrument.countDocuments(query),
  ]);

  const result = {
    instruments,
    total,
    page: pageNum,
    pageSize,
    totalPages: Math.ceil(total / pageSize),
  };

  // Cache for 24 hours
  await setCache(cacheKey, result, 86400);

  res.json(result);
}));

export default router;

import { Router } from 'express';
import { verifyJWT, isOwner, isValidObjectId } from '../middleware/authMiddleware.js';
import { asyncHandler, createError } from '../middleware/errorHandler.js';
import { validate, monteCarloSchema } from '../validation/schemas.js';
import { runMonteCarloWithGoal, getInstrumentVolatility } from '../services/monteCarloEngine.js';
import { getLiveInstrumentParams } from '../services/marketDataService.js';
import { calculatePostTaxReturn } from '../services/postTaxCalculator.js';
import FinancialProfile from '../models/FinancialProfile.js';
import { getCache, setCache } from '../config/redis.js';

const router = Router();

/**
 * POST /api/montecarlo/montecarlo [Protected]
 * Run Monte Carlo simulation for a specific instrument.
 *
 * When a profileId is provided, the simulation uses:
 *   1. Live Nifty-derived volatility params (from AMFI/Yahoo Finance)
 *   2. Post-tax adjusted returns (from the user's marginal slab)
 */
router.post('/montecarlo', verifyJWT, validate(monteCarloSchema), asyncHandler(async (req, res) => {
  const { instrument, monthly_investment, years, target_amount, profileId, current_savings } = req.body;

  // ── Step 1: Fetch live instrument parameters (Nifty-derived for equity) ──
  const liveResult = await getLiveInstrumentParams();
  const liveParams = liveResult.params[instrument]
    || getInstrumentVolatility(instrument);

  let effectiveRate = liveParams.mean;
  let effectiveVolatility = liveParams.stdDev;
  let dataSource = liveParams.source || 'static';
  let postTaxInfo = null;

  // ── Step 2: If profileId provided, compute post-tax adjusted rate ──
  if (profileId) {
    if (!isValidObjectId(profileId)) {
      throw createError(400, 'Invalid profileId in montecarlo', 'Invalid profile ID.');
    }

    const profile = await FinancialProfile.findById(profileId).lean();
    if (!profile) {
      throw createError(404, `Profile not found for Monte Carlo: ${profileId}`, 'Profile not found.');
    }

    // Authorization check
    if (!isOwner(profile, req.user.userId)) {
      throw createError(403, `Unauthorized MC profile access: ${profileId}`, 'Access denied.');
    }

    const annualIncome = profile.annualIncome || (profile.income * 12);
    const regime = profile.taxRegime || 'new';

    try {
      const postTaxResult = calculatePostTaxReturn(
        instrument,
        liveParams.mean,
        annualIncome,
        years,
        regime,
        monthly_investment,   // monthlySIP for accurate FD TDS / ELSS LTCG
        profile.age || 30     // userAge for senior citizen TDS thresholds
      );

      effectiveRate = postTaxResult.postTaxReturn;
      postTaxInfo = {
        nominal_rate: liveParams.mean,
        post_tax_rate: postTaxResult.postTaxReturn,
        tax_type: postTaxResult.taxType,
        tax_rate: postTaxResult.taxRate,
        tds_applicable: postTaxResult.tdsApplicable || false,
        regime,
      };
    } catch (taxErr) {
      console.warn('[MonteCarlo] Post-tax calculation failed, using pre-tax rate:', taxErr.message);
    }
  }

  // ── Step 3: Check Redis cache ──
  // Round effectiveRate to 4 decimal places to avoid cache fragmentation from float precision
  const rateKey = effectiveRate.toFixed(4);
  const volatilityKey = effectiveVolatility.toFixed(4);
  const targetKey = target_amount === undefined || target_amount === null
    ? 'none'
    : Number(target_amount).toFixed(0);
  const savingsKey = current_savings === undefined || current_savings === null
    ? '0'
    : Number(current_savings).toFixed(0);
  const cacheKey = `mc:${req.user.userId}:${instrument}:${years}:${monthly_investment}:${savingsKey}:${targetKey}:${rateKey}:${volatilityKey}`;
  const cached = await getCache(cacheKey);
  if (cached) return res.json({ ...cached, cached: true });

  // ── Step 4: Run Monte Carlo simulation with live + post-tax params ──
  const result = runMonteCarloWithGoal({
    monthlyInvestment: monthly_investment,
    postTaxAnnualReturn: effectiveRate,
    annualVolatility: effectiveVolatility,
    years,
    simulations: 10000,
    targetAmount: target_amount || null,
    currentSavings: current_savings || 0,
  });

  // ── Step 5: Build Recharts-friendly chart data ──
  const chartData = result.years_array.map((yr, i) => ({
    year: yr,
    p10: result.p10[i],
    p25: result.p25[i],
    p50: result.p50[i],
    p75: result.p75[i],
    p90: result.p90[i],
    mean: result.mean[i],
    // Inflation-adjusted (real) values
    p10_real: result.p10_real ? result.p10_real[i] : undefined,
    p50_real: result.p50_real ? result.p50_real[i] : undefined,
    p90_real: result.p90_real ? result.p90_real[i] : undefined,
    standard_error: result.standard_error ? result.standard_error[i] : undefined,
  }));

  // Confidence interval width: how tight the estimates are
  // Narrower = more reliable. CI_width = (p75 - p25) / p50 at terminal year
  const termIdx = result.p50.length - 1;
  const ciWidth = termIdx >= 0 && result.p50[termIdx] > 0
    ? parseFloat(((result.p75[termIdx] - result.p25[termIdx]) / result.p50[termIdx]).toFixed(3))
    : null;

  const response = {
    instrument,
    years,
    monthly_investment,
    chartData,
    goal_probability: result.goal_probability,
    target_amount: result.target_amount,
    simulations_run: result.simulations_run,
    variance_reduction: result.variance_reduction || 'none',
    percentile_summary: {
      p10: result.p10[termIdx],
      p25: result.p25[termIdx],
      p50: result.p50[termIdx],
      p75: result.p75[termIdx],
      p90: result.p90[termIdx],
    },
    percentile_summary_real: result.p50_real ? {
      p10: result.p10_real[termIdx],
      p25: result.p25_real[termIdx],
      p50: result.p50_real[termIdx],
      p75: result.p75_real[termIdx],
      p90: result.p90_real[termIdx],
    } : null,
    confidence_interval_width: ciWidth,
    data_source: dataSource,
    post_tax_rate_used: effectiveRate,
    volatility_used: effectiveVolatility,
    nifty_derived: dataSource === 'live',
    post_tax_info: postTaxInfo,
    sequence_of_returns_risk: result.sequence_of_returns_risk || null,
    sharpe_ratio_sensitivity: result.sharpe_ratio_sensitivity || null,
    inflation_rate: result.inflation_rate || 0.05,
    cached: false,
  };

  // Cache for 30 minutes
  await setCache(cacheKey, response, 1800);
  res.json(response);
}));

export default router;

/**
 * WealthGenie Portfolio Optimisation Route
 * ─────────────────────────────────────────
 * POST /api/portfolio/optimise
 *
 * Accepts an asset universe and strategy, computes post-tax returns
 * for the authenticated user's tax profile, and returns optimal weights.
 *
 * @module routes/portfolio
 */

import { Router } from 'express';
import { verifyJWT, isOwner, isValidObjectId } from '../middleware/authMiddleware.js';
import { asyncHandler, createError } from '../middleware/errorHandler.js';
import { optimisePortfolio, computeRebalance } from '../services/portfolioEngine.js';
import { calculatePostTaxReturnSafe } from '../services/postTaxCalculator.js';
import { INSTRUMENT_PARAMS } from '../services/instrumentConstants.js';
import FinancialProfile from '../models/FinancialProfile.js';
import { validate, rebalanceSchema } from '../validation/schemas.js';

const router = Router();

/** Default asset universe when client doesn't specify */
const DEFAULT_ASSETS = ['Equity_MF', 'Debt_MF', 'Gold', 'PPF', 'FD'];

/** Allowed optimisation strategies */
const VALID_STRATEGIES = ['min_variance', 'max_sharpe', 'risk_parity'];

/**
 * POST /api/portfolio/optimise [Protected]
 *
 * Body:
 *   profileId  {string}    — MongoDB ObjectId for the user's FinancialProfile
 *   assets     {string[]}  — (optional) asset classes to include (default: DEFAULT_ASSETS)
 *   strategy   {string}    — (optional) 'min_variance' | 'max_sharpe' | 'risk_parity' (default: 'max_sharpe')
 *
 * Response:
 *   {
 *     strategy,
 *     weights:             { asset: weight },
 *     expected_return,
 *     volatility,
 *     sharpe_ratio,
 *     risk_contributions?  (only for risk_parity)
 *   }
 */
router.post(
  '/optimise',
  verifyJWT,
  asyncHandler(async (req, res) => {
    const { profileId, assets, strategy } = req.body;

    /* ── Validate profileId ─────────────────────────────────────────── */
    if (!profileId || !isValidObjectId(profileId)) {
      throw createError(400, `Invalid profileId: ${profileId}`, 'A valid profile ID is required.');
    }

    /* ── Validate strategy ──────────────────────────────────────────── */
    const selectedStrategy = strategy || 'max_sharpe';
    if (!VALID_STRATEGIES.includes(selectedStrategy)) {
      throw createError(
        400,
        `Invalid strategy: ${strategy}`,
        `Strategy must be one of: ${VALID_STRATEGIES.join(', ')}`
      );
    }

    /* ── Validate and resolve asset keys ────────────────────────────── */
    const assetKeys = Array.isArray(assets) && assets.length > 0 ? assets : DEFAULT_ASSETS;

    // Ensure every requested asset exists in INSTRUMENT_PARAMS
    for (const key of assetKeys) {
      if (!INSTRUMENT_PARAMS[key]) {
        throw createError(
          400,
          `Unknown asset key: ${key}`,
          `"${key}" is not a recognised instrument. Check /api/instruments for valid keys.`
        );
      }
    }

    if (assetKeys.length < 2) {
      throw createError(
        400,
        'At least 2 assets required for portfolio optimisation',
        'Please provide at least 2 asset classes for meaningful diversification.'
      );
    }

    /* ── Fetch profile ──────────────────────────────────────────────── */
    const profile = await FinancialProfile.findById(profileId).lean();
    if (!profile) {
      throw createError(404, `Profile not found: ${profileId}`, 'Financial profile not found.');
    }
    if (!isOwner(profile, req.user.userId)) {
      throw createError(403, `Unauthorised profile access: ${profileId}`, 'Access denied.');
    }

    /* ── Compute post-tax returns for each asset ────────────────────── */
    const postTaxReturns = assetKeys.map((key) => {
      const nominalRate = INSTRUMENT_PARAMS[key].nominalRate / 100; // decimal
      const ptResult = calculatePostTaxReturnSafe(
        key,
        nominalRate,
        profile.annualIncome,
        profile.investmentHorizon || 15,
        profile.taxRegime || 'new'
      );
      return ptResult.postTaxReturn; // already decimal
    });

    /* ── Run optimiser ──────────────────────────────────────────────── */
    const result = optimisePortfolio(assetKeys, postTaxReturns, selectedStrategy);

    /* ── Format response ────────────────────────────────────────────── */
    const response = {
      strategy: result.strategy,
      weights: result.weights,
      expected_return: result.expectedReturn,
      volatility: result.volatility,
    };

    if (result.sharpe !== undefined) {
      response.sharpe_ratio = result.sharpe;
    }
    if (result.riskContributions) {
      response.risk_contributions = result.riskContributions;
    }

    res.json(response);
  })
);

/**
 * POST /api/portfolio/rebalance [Protected]
 * Calculates weight drift, overweight/underweight positions, suggested correction actions,
 * and before/after CAGRs and risk scores.
 */
router.post(
  '/rebalance',
  verifyJWT,
  validate(rebalanceSchema),
  asyncHandler(async (req, res) => {
    const { current_allocation, target_allocation, threshold, partial_ratio, holding_months } = req.body;

    const result = computeRebalance(
      current_allocation,
      target_allocation,
      threshold,
      partial_ratio,
      holding_months
    );

    res.json(result);
  })
);

export default router;

import { Router } from 'express';
import { verifyJWT } from '../middleware/authMiddleware.js';
import { asyncHandler, createError } from '../middleware/errorHandler.js';
import { validate, profileSchema } from '../validation/schemas.js';
import { computeTax, getTaxSlab, compareTaxRegimes } from '../services/taxEngine.js';
import { getRiskProfile } from '../services/riskProfiler.js';
import FinancialProfile from '../models/FinancialProfile.js';
import { delCache, redisClient, redisAvailable } from '../config/redis.js';
import { idempotency } from '../middleware/idempotency.js';

const router = Router();

// Profile creation throttle — max profiles per user per hour
// STATELESS: Uses shared Redis counter. No per-process in-memory state.
const PROFILE_RATE_LIMIT = 10;

async function checkProfileRateLimit(userId) {
  if (!redisAvailable || !redisClient) {
    // Without Redis, skip throttle rather than diverging per-process state.
    return true;
  }
  try {
    const key = `profile:ratelimit:${userId}`;
    const count = await redisClient.incr(key);
    if (count === 1) await redisClient.expire(key, 3600);
    return count <= PROFILE_RATE_LIMIT;
  } catch {
    // Redis failure — allow request through to avoid blocking users.
    return true;
  }
}

/**
 * POST /api/profile/build [Protected]
 * Builds a financial profile with tax computation and risk profiling.
 */
router.post('/build', verifyJWT, idempotency(), validate(profileSchema), asyncHandler(async (req, res) => {
  // Throttle: prevent unbounded profile creation
  if (process.env.DISABLE_RATE_LIMIT !== 'true' && !checkProfileRateLimit(req.user.userId)) {
    throw createError(429, `Profile rate limit for user ${req.user.userId}`,
      `Too many profile submissions. Maximum ${PROFILE_RATE_LIMIT} per hour.`);
  }

  const {
    monthly_income, age, monthly_savings, regime, investment_horizon,
    liquid_savings, existing_debt, dependents, emergency_fund_months,
    risk_tolerance, goal_type
  } = req.body;

  const annualIncome = monthly_income * 12;
  const taxRegime = regime || 'new';

  // Compute tax
  const taxResult = computeTax(annualIncome, taxRegime);
  const marginalRate = getTaxSlab(annualIncome, taxRegime);
  const taxComparison = compareTaxRegimes(annualIncome);

  // Compute risk profile (now uses 3-factor model: age + income + horizon, with savings penalty)
  const riskProfile = getRiskProfile(age, annualIncome, investment_horizon, 0, dependents || 0, monthly_savings, existing_debt || 0);

  // Investable amount = monthly savings (pre-validated to be < income)
  const investableAmount = monthly_savings;

  // Self-check invariant: riskScore must align with riskCategory
  // These ranges MUST match the thresholds in riskProfiler.js getRiskProfile()
  //   >=80 → Aggressive, >=60 → Mod-Agg, >=40 → Moderate, >=20 → Con-Mod, <20 → Conservative
  const SCORE_RANGES = {
    'Aggressive': [80, 100], 'Moderate-Aggressive': [60, 79],
    'Moderate': [40, 59], 'Conservative-Moderate': [20, 39], 'Conservative': [0, 19],
  };
  const expectedRange = SCORE_RANGES[riskProfile.category];
  if (expectedRange && (riskProfile.riskScore < expectedRange[0] || riskProfile.riskScore > expectedRange[1])) {
    console.error(
      `[Profile INVARIANT VIOLATION] riskScore ${riskProfile.riskScore} does not match `
      + `category '${riskProfile.category}' (expected ${expectedRange[0]}-${expectedRange[1]}). `
      + `This indicates a drift between riskProfiler.js thresholds and profile.js SCORE_RANGES. `
      + `Profile will still be saved, but risk alignment may be inconsistent.`
    );
  }

  // Save to MongoDB
  const profile = await FinancialProfile.create({
    userId: req.user.userId,
    income: monthly_income,
    age,
    savings: monthly_savings,
    annualIncome,
    taxSlab: marginalRate,
    effectiveTaxRate: taxResult.effectiveRate,
    taxRegime,
    riskCategory: riskProfile.category,
    riskScore: riskProfile.riskScore,
    riskDescription: riskProfile.description,
    recommendedEquityAllocation: riskProfile.recommendedEquityAllocation,
    investableAmount,
    investmentHorizon: investment_horizon,
    liquid_savings: liquid_savings || 0,
    existing_debt: existing_debt || 0,
    dependents: dependents || 0,
    emergency_fund_months: emergency_fund_months || 0,
    risk_tolerance: risk_tolerance || 'Moderate',
    goal_type: goal_type || 'wealth-building'
  });

  // Invalidate ALL chatbot system prompt caches for this user
  // so the AI picks up the latest financial numbers immediately
  try {
    const prefix = `chat:sysprompt_v3:${req.user.userId}:`;
    await delCache(prefix + profile._id);
    // Also try to invalidate any previous profile's cached prompt
    const prevProfile = await FinancialProfile.findOne({
      userId: req.user.userId,
      _id: { $ne: profile._id },
    }).sort({ createdAt: -1 }).lean();
    if (prevProfile) await delCache(prefix + prevProfile._id);
  } catch (redisErr) {
    console.warn('[Profile] Cache invalidation failed (non-critical):', redisErr.message);
  }

  res.status(201).json({
    profileId: profile._id,
    taxSlab: marginalRate,
    effectiveTaxRate: taxResult.effectiveRate,
    taxDetails: taxResult,
    taxComparison,
    riskCategory: riskProfile.category,
    riskScore: riskProfile.riskScore,
    riskDescription: riskProfile.description,
    recommendedEquityAllocation: riskProfile.recommendedEquityAllocation,
    annual_income: annualIncome,
    investable_amount: investableAmount,
  });
}));

/**
 * PUT /api/profile/:profileId [Protected]
 * Updates a financial profile with optimistic concurrency control (OCC).
 */
router.put('/:profileId', verifyJWT, validate(profileSchema), asyncHandler(async (req, res) => {
  const { profileId } = req.params;
  const expectedVersion = req.body.version;

  const profile = await FinancialProfile.findById(profileId);
  if (!profile) {
    throw createError(404, 'Profile not found', 'Profile not found.');
  }

  if (profile.userId.toString() !== req.user.userId) {
    throw createError(403, 'Access denied', 'Access denied.');
  }

  // 1. Fail-fast version check
  if (expectedVersion !== undefined && profile.__v !== expectedVersion) {
    return res.status(409).json({
      error: 'Conflict',
      message: 'Version conflict. Document has been modified concurrently by another process.'
    });
  }

  const {
    monthly_income, age, monthly_savings, regime, investment_horizon,
    liquid_savings, existing_debt, dependents, emergency_fund_months,
    risk_tolerance, goal_type
  } = req.body;

  // Apply edits
  profile.income = monthly_income;
  profile.age = age;
  profile.savings = monthly_savings;
  profile.annualIncome = monthly_income * 12;
  profile.taxRegime = regime || 'new';
  profile.investmentHorizon = investment_horizon;
  profile.liquid_savings = liquid_savings || 0;
  profile.existing_debt = existing_debt || 0;
  profile.dependents = dependents || 0;
  profile.emergency_fund_months = emergency_fund_months || 0;
  profile.risk_tolerance = risk_tolerance || 'Moderate';
  profile.goal_type = goal_type || 'wealth-building';

  // Recompute tax & risk profile
  const taxResult = computeTax(profile.annualIncome, profile.taxRegime);
  const marginalRate = getTaxSlab(profile.annualIncome, profile.taxRegime);
  const riskProfile = getRiskProfile(age, profile.annualIncome, investment_horizon, 0, profile.dependents || 0, monthly_savings, profile.existing_debt || 0);

  profile.taxSlab = marginalRate;
  profile.effectiveTaxRate = taxResult.effectiveRate;
  profile.riskCategory = riskProfile.category;
  profile.riskScore = riskProfile.riskScore;
  profile.riskDescription = riskProfile.description;
  profile.recommendedEquityAllocation = riskProfile.recommendedEquityAllocation;
  profile.investableAmount = monthly_savings;

  try {
    await profile.save();
  } catch (err) {
    if (err.name === 'VersionError') {
      return res.status(409).json({
        error: 'Conflict',
        message: 'Version conflict. Document has been modified concurrently.'
      });
    }
    throw err;
  }

  res.json({
    status: 'success',
    profile
  });
}));

export default router;

import { Router } from 'express';
import { verifyJWT, isOwner, isValidObjectId } from '../middleware/authMiddleware.js';
import { asyncHandler, createError } from '../middleware/errorHandler.js';
import { validate, projectionSchema } from '../validation/schemas.js';
import FinancialProfile from '../models/FinancialProfile.js';
import { generateProjections } from '../services/projectionEngine.js';
import { calculatePostTaxReturnSafe } from '../services/postTaxCalculator.js';
import { computeXIRR, computeSIPXIRR } from '../services/xirrCalculator.js';
import { buildRateLookup } from '../services/instrumentConstants.js';

const router = Router();

const RATE_LOOKUP = buildRateLookup();

/**
 * POST /api/projection [Protected]
 * Generate wealth projections for multiple instruments over time.
 */
router.post('/', verifyJWT, validate(projectionSchema), asyncHandler(async (req, res) => {
  const { profileId, instruments, monthly_investment, years } = req.body;

  if (!isValidObjectId(profileId)) {
    throw createError(400, 'Invalid profileId', 'Invalid profile ID.');
  }

  const profile = await FinancialProfile.findById(profileId).lean();
  if (!profile) {
    throw createError(404, `Profile not found: ${profileId}`, 'Profile not found.');
  }

  // Authorization: verify the profile belongs to the requesting user
  if (!isOwner(profile, req.user.userId)) {
    throw createError(403, `Unauthorized profile access: ${profileId}`, 'Access denied.');
  }

  const investAmount = monthly_investment || profile.savings;
  const projYears = years || [5, 10, 15, 20];

  // Guard: reject zero or negative investment amounts instead of producing misleading flat-line projections
  if (!Number.isFinite(investAmount) || investAmount <= 0) {
    throw createError(400,
      `Invalid investment amount: ${investAmount} (monthly_investment: ${monthly_investment}, profile.savings: ${profile.savings})`,
      'Monthly investment amount must be greater than zero.'
    );
  }

  // Build instrument list with post-tax rates
  const instKeys = instruments || ['FD', 'ELSS', 'Equity_MF', 'Debt_MF'];
  const instList = instKeys.map(key => {
    const nominalRate = RATE_LOOKUP[key];
    if (nominalRate === undefined) {
      console.warn(`[Projection] Unknown instrument key: '${key}'. Using 7.0% default. Add this key to RATE_LOOKUP.`);
    }
    const safeRate = nominalRate ?? 7.0;
    const ptResult = calculatePostTaxReturnSafe(
      key,
      safeRate / 100,
      profile.annualIncome,
      profile.investmentHorizon || 15,
      profile.taxRegime || 'new'
    );

    // Invariant check: post-tax rate should not exceed nominal rate
    if (ptResult.effectiveYield > safeRate + 0.01) {
      console.error(`[Projection INVARIANT] ${key}: effectiveYield ${ptResult.effectiveYield}% exceeds nominal ${safeRate}%. Clamping.`);
      ptResult.effectiveYield = safeRate;
    }

    return { name: key, type: key, postTaxRate: ptResult.effectiveYield };
  });

  const postTaxRates = {};
  instList.forEach(i => { postTaxRates[i.name] = i.postTaxRate; });

  const projections = generateProjections(investAmount, instList, postTaxRates, projYears);

  res.json(projections);
}));

/**
 * POST /api/projection/xirr [Protected]
 * Compute XIRR (Extended Internal Rate of Return) for irregular cashflows.
 * Uses Newton-Raphson iteration — the institutional standard for evaluating
 * SIP performance where each installment has a different holding period.
 *
 * Body: { cashflows: [{amount, date}], guess?: number }
 *   OR: { monthlySIP, months, currentValue }  (SIP convenience mode)
 */
router.post('/xirr', verifyJWT, asyncHandler(async (req, res) => {
  const { cashflows, monthlySIP, months, currentValue, guess } = req.body;

  // SIP convenience mode
  if (monthlySIP && months && currentValue) {
    if (!Number.isFinite(monthlySIP) || monthlySIP <= 0) {
      throw createError(400, 'Invalid monthlySIP', 'Monthly SIP must be a positive number.');
    }
    if (!Number.isFinite(months) || months < 1 || months > 1200) {
      throw createError(400, 'Invalid months', 'Months must be between 1 and 1200 (max 100 years).');
    }
    if (!Number.isFinite(currentValue) || currentValue <= 0) {
      throw createError(400, 'Invalid currentValue', 'Current value must be a positive number.');
    }
    const result = computeSIPXIRR(monthlySIP, months, currentValue);
    return res.json({ mode: 'sip', ...result });
  }

  // General XIRR mode
  if (!Array.isArray(cashflows) || cashflows.length < 2) {
    throw createError(400, 'Invalid cashflows', 'Provide at least 2 cashflows with amount and date.');
  }

  if (cashflows.length > 1000) {
    throw createError(400, 'Too many cashflows', 'Maximum 1000 cashflows allowed to prevent server overhead.');
  }

  // Validate each cashflow
  for (const cf of cashflows) {
    if (!Number.isFinite(cf.amount)) {
      throw createError(400, `Invalid cashflow amount: ${cf.amount}`, 'Each cashflow must have a finite amount.');
    }
    if (!cf.date) {
      throw createError(400, 'Missing cashflow date', 'Each cashflow must have a date.');
    }
    const parsedDate = new Date(cf.date);
    if (!Number.isFinite(parsedDate.getTime())) {
      throw createError(400, `Invalid cashflow date: ${cf.date}`, 'Each cashflow must have a valid date.');
    }
  }

  let safeGuess = guess;
  if (guess !== undefined) {
    safeGuess = Number(guess);
    if (!Number.isFinite(safeGuess)) {
      throw createError(400, `Invalid XIRR guess: ${guess}`, 'Guess must be a finite number.');
    }
  }

  const result = computeXIRR(cashflows, safeGuess);
  res.json({ mode: 'general', ...result });
}));

export default router;

import { Router } from 'express';
import { verifyJWT, isOwner, isValidObjectId } from '../middleware/authMiddleware.js';
import { asyncHandler, createError } from '../middleware/errorHandler.js';
import { validate, recommendSchema, updateWeightsSchema } from '../validation/schemas.js';
import FinancialProfile from '../models/FinancialProfile.js';
import Recommendation from '../models/Recommendation.js';
import { getMLPrediction } from '../services/mlClient.js';
import { getTaxSlab } from '../services/taxEngine.js';
import { generateAdvisory } from '../services/geminiService.js';
import { runPipeline } from '../services/RecommendationPipeline.js';
import crypto from 'crypto';
import { getCache, setCache, delCache } from '../config/redis.js';
import { RISK_FREE_RATE, DISCLAIMER } from '../services/instrumentConstants.js';

const router = Router();

function buildProfileHash(profile) {
  return crypto.createHash('sha256').update(JSON.stringify({
    age: profile.age,
    income: profile.annualIncome,
    savings: profile.savings,
    risk: profile.riskCategory,
    regime: profile.taxRegime,
    horizon: profile.investmentHorizon,
  })).digest('hex').substring(0, 16);
}

export function buildRecommendationCacheKey(userId, profileId, profile) {
  return `recommendation:${userId}:${profileId}:${buildProfileHash(profile)}`;
}

// DISCLAIMER and RISK_FREE_RATE imported from instrumentConstants.js

/**
 * POST /api/recommend [Protected]
 * Generate investment recommendations for a financial profile.
 */
router.post('/', verifyJWT, validate(recommendSchema), asyncHandler(async (req, res) => {
  const { profileId } = req.body;

  if (!isValidObjectId(profileId)) {
    throw createError(400, 'Invalid profileId format', 'Invalid profile ID.');
  }

  const profile = await FinancialProfile.findById(profileId).lean();
  if (!profile) {
    throw createError(404, `Profile not found: ${profileId}`, 'Profile not found.');
  }

  // Authorization: verify the profile belongs to the requesting user
  if (!isOwner(profile, req.user.userId)) {
    throw createError(403, `User ${req.user.userId} tried to access profile ${profileId}`, 'Access denied.');
  }

  // Check Redis cache to prevent redundant recalculations
  const cacheKey = buildRecommendationCacheKey(req.user.userId, profile._id, profile);

  const cachedResult = await getCache(cacheKey);
  if (cachedResult) {
    return res.json(cachedResult);
  }

  // Call ML microservice
  const mlResult = await getMLPrediction({
    age: profile.age,
    annual_income: profile.annualIncome,
    monthly_savings: profile.savings,
    risk_category: profile.riskCategory,
    liquid_savings: profile.liquid_savings,
    existing_debt: profile.existing_debt,
    dependents: profile.dependents,
    emergency_fund_months: profile.emergency_fund_months,
    risk_tolerance: profile.risk_tolerance,
    goal_type: profile.goal_type,
    investment_horizon: profile.investmentHorizon || 15
  }, req.correlationId);

  // ── Run the metadata-driven RecommendationPipeline ──────────────
  // This replaces the previous hardcoded demographic & tax overrides
  // with a modular pipeline: eligibility → scoring → ranking → diversity
  const { instruments, confidenceScores } = runPipeline(profile, mlResult);

  if (instruments.length === 0) {
    throw createError(502, 'RecommendationPipeline returned no instruments', 'Recommendation engine returned empty results.');
  }

  // Portfolio-level expected yield (weighted average of post-tax returns)
  const portfolioYield = parseFloat(
    instruments.reduce((s, i) => s + (i.effectiveYield * i.allocationWeight), 0).toFixed(2)
  );

  // Call Groq/Gemini for advisory text
  const marginalRate = getTaxSlab(profile.annualIncome, profile.taxRegime);
  const advisory = await generateAdvisory({
    age: profile.age,
    annualIncome: profile.annualIncome,
    monthlySavings: profile.savings,
    taxSlab: marginalRate,
    riskCategory: profile.riskCategory,
    instruments: instruments.map(i => ({ name: i.name, type: i.type, postTaxReturn: i.postTaxReturn })),
    horizon: profile.investmentHorizon || 15,
    shapExplanation: mlResult.explanation || null,
  });

  // Save recommendation to DB
  const rec = await Recommendation.create({
    userId: req.user.userId,
    profileId: profile._id,
    instruments,
    advisoryText: advisory.text,
    confidenceScores,
    mlFallback: mlResult.fallback || false,
    modelVersion: mlResult.model_version || (mlResult.fallback ? 'rule_fallback' : '2.0'),
  });

  const result = {
    recommendationId: rec._id,
    instruments,
    ranked: true,
    advisory_text: advisory.text,
    confidence_scores: confidenceScores,
    decision_path: mlResult.decision_path,
    explanation: mlResult.explanation || null,
    ml_fallback: mlResult.fallback || false,
    model_version: rec.modelVersion,
    portfolio_yield: portfolioYield,
    risk_free_rate: parseFloat((RISK_FREE_RATE * 100).toFixed(2)),
    disclaimer: DISCLAIMER,
  };

  // Cache for 24 hours
  await setCache(cacheKey, result, 86400);

  res.json(result);
}));

/**
 * POST /api/recommend/weights [Protected]
 * Updates allocation weights of a recommendation.
 */
router.post('/weights', verifyJWT, validate(updateWeightsSchema), asyncHandler(async (req, res) => {
  const { profileId, weights } = req.body;

  const profile = await FinancialProfile.findById(profileId).lean();
  if (!profile) {
    throw createError(404, `Profile not found: ${profileId}`, 'Profile not found.');
  }

  if (!isOwner(profile, req.user.userId)) {
    throw createError(403, `Access denied`, 'Access denied.');
  }

  // Find the latest recommendation for this profile
  const recommendation = await Recommendation.findOne({ profileId }).sort({ generatedAt: -1 });
  if (!recommendation) {
    throw createError(404, 'No recommendation found to update', 'No recommendation found.');
  }

  // Update weights on instruments
  const parsedWeights = {};
  let totalWeight = 0;
  for (const [k, v] of Object.entries(weights || {})) {
    const val = Number(v) || 0;
    if (val < 0) continue;
    parsedWeights[k] = val;
    totalWeight += val;
  }

  if (totalWeight <= 0) {
    throw createError(400, 'Invalid weights', 'Total weights must be greater than zero.');
  }

  // Map of weights normalized to sum to exactly 1.0
  const normWeights = {};
  for (const [k, v] of Object.entries(parsedWeights)) {
    normWeights[k.toUpperCase()] = v / totalWeight;
  }

  // Update the recommendation instruments
  recommendation.instruments.forEach(inst => {
    const weight = normWeights[inst.type.toUpperCase()] ?? 0;
    inst.allocationWeight = parseFloat(weight.toFixed(4));
  });

  // Re-normalize instruments weights to sum to EXACTLY 1.0 (to avoid rounding issues)
  const instWeightSum = recommendation.instruments.reduce((s, i) => s + i.allocationWeight, 0);
  if (instWeightSum > 0 && Math.abs(instWeightSum - 1.0) > 0.0001) {
    const maxIdx = recommendation.instruments.reduce((mi, w, i, arr) => w.allocationWeight > arr[mi].allocationWeight ? i : mi, 0);
    recommendation.instruments[maxIdx].allocationWeight = parseFloat((recommendation.instruments[maxIdx].allocationWeight + (1.0 - instWeightSum)).toFixed(4));
  }

  await recommendation.save();

  // Invalidate Redis cache for this recommendation
  const cacheKey = buildRecommendationCacheKey(req.user.userId, profile._id, profile);
  await delCache(cacheKey);

  res.json({
    status: 'success',
    message: 'Recommendation weights updated successfully.',
    instruments: recommendation.instruments,
  });
}));

export default router;

import { Router } from 'express';
import { asyncHandler, createError } from '../middleware/errorHandler.js';
import { validateQuery, taxComputeSchema, taxCompareSchema } from '../validation/schemas.js';
import { computeTax, compareTaxRegimes, isFYVerified, CURRENT_FY } from '../services/taxEngine.js';
import { CESS_RATE } from '../services/instrumentConstants.js';

const router = Router();

function _parseTaxDeductionsFromQuery(query) {
  return {
    section80C: Number(query.section80C) || 0,
    nps80CCD1B: Number(query.nps80CCD1B) || 0,
    nps80CCD2: Number(query.nps80CCD2) || 0,
    basicSalary: query.basicSalary !== undefined ? Number(query.basicSalary) : undefined,
    isGovtEmployee: query.isGovtEmployee === 'true' || query.isGovtEmployee === true,
    section80D: Number(query.section80D) || 0,
    section80D_self: query.section80D_self !== undefined ? Number(query.section80D_self) : undefined,
    section80D_parents: query.section80D_parents !== undefined ? Number(query.section80D_parents) : undefined,
    parents_senior: query.parents_senior === 'true' || query.parents_senior === true,
    self_senior: query.self_senior === 'true' || query.self_senior === true,
    hra: Number(query.hra) || 0,
    homeLoanInterest: Number(query.homeLoanInterest) || 0,
    other: Number(query.other) || 0,
    age: query.age !== undefined ? Number(query.age) : undefined,
  };
}

/**
 * GET /api/tax/compute?income=1200000&regime=new
 * Compute tax for a specific income and regime.
 */
router.get('/compute', validateQuery(taxComputeSchema), asyncHandler(async (req, res) => {
  // Joi coerces query strings to numbers via taxComputeSchema
  const income = Number(req.query.income);
  const regime = req.query.regime || 'new';

  if (!Number.isFinite(income) || income < 0) {
    return res.status(400).json({ error: 'Income must be a valid positive number.' });
  }

  const deductions = _parseTaxDeductionsFromQuery(req.query);
  const result = computeTax(income, regime, deductions, req.query.incomeSource, req.query.fiscalYear);

  const fiscalYear = result.fiscalYear || req.query.fiscalYear || CURRENT_FY;
  const verified = isFYVerified(fiscalYear);
  const response = { ...result, fiscal_year: fiscalYear, verified };
  if (!verified) {
    response.warning = `UNVERIFIED: Tax slabs for ${fiscalYear} have not been confirmed against an official source. Do not rely on this for tax filing.`;
  }
  res.json(response);
}));

/**
 * GET /api/tax/compare?income=1200000
 * Compare both tax regimes and return the recommended one.
 */
router.get('/compare', validateQuery(taxCompareSchema), asyncHandler(async (req, res) => {
  const income = Number(req.query.income);

  if (!Number.isFinite(income) || income < 0) {
    return res.status(400).json({ error: 'Income must be a valid positive number.' });
  }

  const deductions = _parseTaxDeductionsFromQuery(req.query);
  const { newRegime, oldRegime, recommended } = compareTaxRegimes(income, deductions, req.query.incomeSource, req.query.fiscalYear);
  const saving = Math.abs(newRegime.taxAmount - oldRegime.taxAmount);

  const fiscalYear = newRegime.fiscalYear || req.query.fiscalYear || CURRENT_FY;
  const verified = isFYVerified(fiscalYear);

  const response = {
    income,
    fiscal_year: fiscalYear,
    verified,
    new_regime: {
      tax: newRegime.taxAmount,
      effective_rate: newRegime.effectiveRate,
      rebate_applied: newRegime.rebateApplied,
      taxable_income: newRegime.taxableIncome,
      standard_deduction: newRegime.standardDeduction,
      marginal_relief_applied: newRegime.marginalReliefApplied || false,
      marginal_relief_amount: newRegime.marginalReliefAmount || 0,
      cess: Math.round(newRegime.taxAmount * CESS_RATE / (1 + CESS_RATE)),
      nps80CCD2: newRegime.nps80CCD2 || 0,
      allowed80D: newRegime.allowed80D || 0,
    },
    old_regime: {
      tax: oldRegime.taxAmount,
      effective_rate: oldRegime.effectiveRate,
      rebate_applied: oldRegime.rebateApplied,
      taxable_income: oldRegime.taxableIncome,
      standard_deduction: oldRegime.standardDeduction,
      marginal_relief_applied: oldRegime.marginalReliefApplied || false,
      marginal_relief_amount: oldRegime.marginalReliefAmount || 0,
      cess: Math.round(oldRegime.taxAmount * CESS_RATE / (1 + CESS_RATE)),
      nps80CCD2: oldRegime.nps80CCD2 || 0,
      allowed80D: oldRegime.allowed80D || 0,
    },
    recommended_regime: recommended,
    saving,
    saving_pct: income > 0 ? parseFloat(((saving / income) * 100).toFixed(2)) : 0,
    saving_with: recommended,
  };
  if (!verified) {
    response.warning = `UNVERIFIED: Tax slabs for ${fiscalYear} have not been confirmed against an official source. Do not rely on this for tax filing.`;
  }
  res.json(response);
}));

export default router;

/**
 * cluster-test.js — Statelessness proof: 50-request load test through LB proxy
 *
 * Sends 50 requests to the load-balanced proxy, verifies:
 *   1. All requests succeed (0 failures)
 *   2. Traffic splits evenly across both backends (~25/25)
 *   3. Health check data is consistent from both instances
 *
 * Usage: node scripts/cluster-test.js [proxyPort]
 * Default proxyPort: 4000
 */

const proxyPort = process.argv[2] || '4000';
const BASE_URL = `http://127.0.0.1:${proxyPort}`;
const TOTAL_REQUESTS = 50;

async function runTest() {
  console.log(`\n╔══════════════════════════════════════════════════════════╗`);
  console.log(`║  STATELESSNESS PROOF — Cluster Load Test                ║`);
  console.log(`╠══════════════════════════════════════════════════════════╣`);
  console.log(`║  Target: ${BASE_URL.padEnd(47)}║`);
  console.log(`║  Requests: ${String(TOTAL_REQUESTS).padEnd(45)}║`);
  console.log(`╚══════════════════════════════════════════════════════════╝\n`);

  const results = { success: 0, fail: 0, backends: {} };
  const latencies = [];

  for (let i = 0; i < TOTAL_REQUESTS; i++) {
    const start = Date.now();
    try {
      const res = await fetch(`${BASE_URL}/api/health`);
      const elapsed = Date.now() - start;
      latencies.push(elapsed);

      const backend = res.headers.get('x-lb-backend') || 'unknown';
      results.backends[backend] = (results.backends[backend] || 0) + 1;

      if (res.ok) {
        const body = await res.json();
        if (body.status === 'UP' || body.status === 'ok') {
          results.success++;
        } else {
          results.fail++;
          console.error(`  [FAIL] Request ${i + 1}: status=${body.status}`);
        }
      } else {
        results.fail++;
        console.error(`  [FAIL] Request ${i + 1}: HTTP ${res.status}`);
      }
    } catch (err) {
      results.fail++;
      const elapsed = Date.now() - start;
      latencies.push(elapsed);
      console.error(`  [FAIL] Request ${i + 1}: ${err.message}`);
    }
  }

  const avgLatency = (latencies.reduce((a, b) => a + b, 0) / latencies.length).toFixed(1);
  const p95 = latencies.sort((a, b) => a - b)[Math.floor(latencies.length * 0.95)];

  console.log(`\n┌──────────────────────────────────────────────────────────┐`);
  console.log(`│  RESULTS                                                 │`);
  console.log(`├──────────────────────────────────────────────────────────┤`);
  console.log(`│  Total:    ${String(TOTAL_REQUESTS).padEnd(46)}│`);
  console.log(`│  Success:  ${String(results.success).padEnd(46)}│`);
  console.log(`│  Failures: ${String(results.fail).padEnd(46)}│`);
  console.log(`│  Avg ms:   ${String(avgLatency).padEnd(46)}│`);
  console.log(`│  P95 ms:   ${String(p95).padEnd(46)}│`);
  console.log(`├──────────────────────────────────────────────────────────┤`);
  console.log(`│  BACKEND DISTRIBUTION                                    │`);
  for (const [backend, count] of Object.entries(results.backends)) {
    const pct = ((count / TOTAL_REQUESTS) * 100).toFixed(0);
    console.log(`│  :${backend.padEnd(8)} → ${String(count).padEnd(4)} requests (${pct}%)${' '.repeat(28 - pct.length - String(count).length)}│`);
  }
  console.log(`└──────────────────────────────────────────────────────────┘`);

  const passed = results.fail === 0 && Object.keys(results.backends).length === 2;
  console.log(`\n${passed ? '✅ PROOF PASSED' : '❌ PROOF FAILED'}: ${results.success}/${TOTAL_REQUESTS} requests succeeded across ${Object.keys(results.backends).length} backends.\n`);

  process.exit(passed ? 0 : 1);
}

runTest().catch(err => {
  console.error('Test runner failed:', err);
  process.exit(1);
});

/**
 * WealthGenie — Backend Recommendation Pipeline
 * ──────────────────────────────────────────────
 * Metadata-driven recommendation service that replaces hardcoded
 * instrument overrides with configurable scoring logic.
 *
 * ARCHITECTURE:
 *   This pipeline is the backend's independent recommendation engine.
 *   It orchestrates four modular stages:
 *     1. Eligibility Filtering  — remove instruments the user cannot hold
 *     2. Scoring                — multi-factor weighted utility per instrument
 *     3. Ranking                — sort by score, apply ML confidence boost
 *     4. Diversity Enforcement  — ensure top-N spans min asset classes
 *
 *   The pipeline consumes:
 *     - The backend's authoritative catalog (server/data/investmentDatabase.js)
 *     - ML confidence scores from mlClient.js
 *     - User profile data from FinancialProfile
 *     - Tax slab computation from taxEngine.js
 *
 *   It does NOT duplicate the frontend scoring engine. Instead it reuses
 *   the existing backend tax infrastructure (getTaxSlab, calculatePostTaxReturnSafe)
 *   and adds only the metadata-driven scoring logic required for independent
 *   backend recommendations.
 */

import { getTaxSlab } from './taxEngine.js';
import { calculatePostTaxReturnSafe } from './postTaxCalculator.js';
import { INSTRUMENT_PARAMS, RISK_FREE_RATE } from './instrumentConstants.js';
import { investmentDatabase } from '../data/investmentDatabase.js';

// ═══════════════════════════════════════════════════════════════════
// PIPELINE CONFIGURATION — centralized, no magic numbers
// ═══════════════════════════════════════════════════════════════════
const PIPELINE_CONFIG = Object.freeze({
  TOP_N: 5,
  MIN_ASSET_CLASSES: 3,

  // Weight ranges
  WEIGHT_FLOOR: 0.5,
  WEIGHT_CEIL: 3.0,

  // Return scoring
  RETURN_MULTIPLIER: 3.5,

  // Risk alignment
  RISK_PERFECT_BONUS: 20,
  RISK_CLOSE_BONUS: 12,
  RISK_MISMATCH_PENALTY: 10,
  RISK_SEVERE_PENALTY: 18,
  VOLATILITY_BASELINE: 0.15,

  // Tax efficiency
  TAX_PENALTY_SCALE: 8,       // (5 - taxEfficiencyScore) * marginalRate * scale

  // Liquidity
  LIQUIDITY_CENTER: 3,
  LIQUIDITY_SCALE: 4,

  // Goal alignment
  GOAL_TAG_POINTS: 5,
  GOAL_TAG_CAP: 15,

  // Horizon match
  HORIZON_PERFECT: 15,
  HORIZON_GOOD: 10,
  HORIZON_PARTIAL: 5,
  HORIZON_LOCK_FIT: 15,
  HORIZON_NO_LOCK: 5,
  HORIZON_SEVERE_MISMATCH_PENALTY: 10,

  // Cost
  COST_FREE_BONUS: 3,
  COST_PENALTY_SCALE: 100,

  // ML confidence integration
  ML_BOOST_WEIGHT: 25,        // points per 1.0 confidence (scaled)
});

// ═══════════════════════════════════════════════════════════════════
// STAGE 1: ELIGIBILITY FILTERING
// ═══════════════════════════════════════════════════════════════════

/**
 * Filter instruments the user is eligible to hold based on metadata.
 * @param {Array} instruments - Full instrument catalog
 * @param {Object} profile - User's financial profile
 * @returns {Array} Eligible instruments
 */
export function filterEligible(instruments, profile) {
  const age = Number(profile.age) || 30;
  const annualIncome = Number(profile.annualIncome) || 0;
  const monthlySavings = Number(profile.savings) || 0;

  return instruments.filter(inv => {
    const elig = inv.eligibility;
    if (!elig) return true; // No eligibility rules = universally eligible

    // Age gate
    if (elig.minAge && age < elig.minAge) return false;
    if (elig.maxAge && age > elig.maxAge) return false;

    // Income gate
    if (elig.minAnnualIncome && annualIncome < elig.minAnnualIncome) return false;

    // Savings gate
    if (elig.minMonthlySavings && monthlySavings < elig.minMonthlySavings) return false;

    // Special: girl child requirement (skip if user doesn't have one)
    if (elig.hasGirlChild && !profile.hasGirlChild) return false;

    return true;
  });
}

// ═══════════════════════════════════════════════════════════════════
// STAGE 2: SCORING — multi-factor weighted utility
// ═══════════════════════════════════════════════════════════════════

/**
 * Parse profile into normalized scoring parameters.
 * Reuses backend's getTaxSlab for marginal rate computation.
 */
function parseProfile(profile) {
  const age = Number(profile.age) || 30;
  const annualIncome = Number(profile.annualIncome) || 600000;
  const savings = Number(profile.savings) || 10000;
  const risk = (profile.riskCategory || 'Moderate').toLowerCase();
  const horizon = Number(profile.investmentHorizon) || 10;
  const goals = profile.goal_type ? [profile.goal_type] : [];
  const taxRegime = profile.taxRegime || 'new';
  const mr = getTaxSlab(annualIncome, taxRegime);

  return { age, annualIncome, savings, risk, horizon, goals, taxRegime, mr };
}

/**
 * Derive dynamic weights from user profile.
 * Mirrors the frontend's weight derivation logic.
 */
function deriveWeights(p) {
  const clamp = (v) => Math.max(PIPELINE_CONFIG.WEIGHT_FLOOR, Math.min(PIPELINE_CONFIG.WEIGHT_CEIL, v));

  // α — Return: long horizon + high risk → prioritize growth
  let alpha = 1.0;
  if (p.horizon >= 15) alpha += 0.5;
  if (p.horizon >= 20) alpha += 0.3;
  if (p.risk === 'aggressive' || p.risk === 'moderate-aggressive') alpha += 0.5;
  else if (p.risk === 'conservative') alpha -= 0.3;

  // β — Risk: older age + low risk → penalize risky instruments
  let beta = 1.0;
  if (p.age >= 50) beta += 0.8;
  else if (p.age >= 40) beta += 0.4;
  if (p.risk === 'conservative') beta += 0.8;
  else if (p.risk === 'aggressive') beta -= 0.4;

  // γ — Tax: high slab → penalize slab-taxed instruments
  let gamma = p.mr > 0 ? (p.mr / 0.312) * 1.5 : 0;

  // δ — Liquidity
  let delta = 0.8;
  const emergencyCover = p.annualIncome > 0 ? (p.savings * 12 / p.annualIncome) : 0;
  if (emergencyCover < 0.2) delta += 0.6;

  // ε — Goal alignment
  let epsilon = p.goals.length > 0 ? 1.2 : 0.5;

  // ζ — Horizon match
  let zeta = 1.0;
  if (p.horizon <= 3) zeta += 0.5;
  if (p.horizon >= 20) zeta += 0.3;

  // η — Cost
  let eta = 0.5;
  if (p.horizon >= 10) eta += 0.3;
  if (p.horizon >= 20) eta += 0.4;

  return {
    alpha: clamp(alpha), beta: clamp(beta), gamma: clamp(gamma),
    delta: clamp(delta), epsilon: clamp(epsilon), zeta: clamp(zeta), eta: clamp(eta),
  };
}

// ── Individual scoring sub-functions ────────────────────────────────

function scoreReturn(postTaxRate) {
  return postTaxRate * PIPELINE_CONFIG.RETURN_MULTIPLIER;
}

function scoreRisk(inv, p) {
  const invRisk = typeof inv.riskLevel === 'number' ? inv.riskLevel : (inv.risk || 3);
  let idealMin, idealMax;
  if (p.risk === 'conservative' || p.risk === 'conservative-moderate') { idealMin = 1; idealMax = 2; }
  else if (p.risk === 'aggressive' || p.risk === 'moderate-aggressive') { idealMin = 3; idealMax = 5; }
  else { idealMin = 2; idealMax = 4; }

  if (invRisk >= idealMin && invRisk <= idealMax) return -PIPELINE_CONFIG.RISK_PERFECT_BONUS;
  const dist = invRisk < idealMin ? (idealMin - invRisk) : (invRisk - idealMax);
  if (dist === 1) return -PIPELINE_CONFIG.RISK_CLOSE_BONUS + PIPELINE_CONFIG.RISK_MISMATCH_PENALTY;

  let penalty = PIPELINE_CONFIG.RISK_SEVERE_PENALTY;
  const vol = inv.volatility;
  if (vol !== undefined && vol !== null) {
    const volExcess = Math.max(0, vol - PIPELINE_CONFIG.VOLATILITY_BASELINE);
    if (p.risk === 'conservative') penalty += volExcess * 40;
  }
  return penalty;
}

function scoreTax(inv, p) {
  const taxEff = inv.taxEfficiencyScore;
  if (taxEff !== undefined && taxEff !== null) {
    return (5 - taxEff) * p.mr * PIPELINE_CONFIG.TAX_PENALTY_SCALE;
  }
  // Fallback: use taxType
  if (inv.taxType === 'eee') return -12;
  if (inv.taxType === 'slab') return p.mr * 20;
  return 0;
}

function scoreLiquidity(inv) {
  const liq = inv.liquidityScore;
  if (liq !== undefined && liq !== null) {
    return Math.max(0, (liq - PIPELINE_CONFIG.LIQUIDITY_CENTER) * PIPELINE_CONFIG.LIQUIDITY_SCALE);
  }
  if (inv.lockIn === 0) return 5;
  if (inv.lockIn <= 3) return 2;
  return 0;
}

function scoreGoal(inv, p) {
  const tags = inv.goalTags;
  if (tags && Array.isArray(tags) && tags.length > 0) {
    const matchCount = p.goals.filter(g => tags.includes(g)).length;
    return Math.min(matchCount * PIPELINE_CONFIG.GOAL_TAG_POINTS, PIPELINE_CONFIG.GOAL_TAG_CAP);
  }
  return 0;
}

function scoreHorizon(inv, p) {
  let score = 0;
  const lockIn = inv.lockIn || 0;
  if (lockIn <= p.horizon) score += PIPELINE_CONFIG.HORIZON_LOCK_FIT;
  if (lockIn === 0) score += PIPELINE_CONFIG.HORIZON_NO_LOCK;

  const ideal = inv.idealHorizon;
  if (ideal && ideal.min !== undefined && ideal.max !== undefined) {
    if (p.horizon >= ideal.min && p.horizon <= ideal.max) {
      score += PIPELINE_CONFIG.HORIZON_PERFECT;
    } else if (p.horizon >= ideal.min - 2 && p.horizon <= ideal.max + 5) {
      score += PIPELINE_CONFIG.HORIZON_GOOD;
    } else if (p.horizon >= ideal.min - 5) {
      score += PIPELINE_CONFIG.HORIZON_PARTIAL;
    }
    if (p.horizon < ideal.min - 5) {
      score -= PIPELINE_CONFIG.HORIZON_SEVERE_MISMATCH_PENALTY;
    }
  }
  return score;
}

function scoreCost(inv) {
  const er = inv.expenseRatio;
  if (er !== undefined && er !== null) {
    if (er === 0) return -PIPELINE_CONFIG.COST_FREE_BONUS;
    return er * PIPELINE_CONFIG.COST_PENALTY_SCALE;
  }
  return 0;
}

/**
 * Compute composite score for a single instrument.
 * @param {Object} inv - Instrument from catalog
 * @param {Object} p - Parsed profile
 * @param {Object} w - Derived weights
 * @param {Object} confScores - ML confidence scores keyed by backend type
 * @returns {Object} Instrument augmented with score and postTaxReturn
 */
function computeInstrumentScore(inv, p, w, confScores) {
  // Use backend's existing post-tax calculator via instrumentConstants
  const rate = inv.expectedReturn || inv.rate || 7.0;
  const backendType = resolveBackendType(inv);
  const postTax = calculatePostTaxReturnSafe(
    backendType, rate / 100,
    p.annualIncome,
    p.horizon,
    p.taxRegime
  );
  const postTaxRate = postTax.effectiveYield || rate;

  // Factor scores
  const returnScore = scoreReturn(postTaxRate);
  const riskPenalty = scoreRisk(inv, p);
  const taxPenalty = scoreTax(inv, p);
  const liquidityBonus = scoreLiquidity(inv);
  const goalBonus = scoreGoal(inv, p);
  const horizonMatch = scoreHorizon(inv, p);
  const costPenalty = scoreCost(inv);

  // Weighted composite
  let score = 0;
  score += w.alpha * returnScore;
  score -= w.beta * riskPenalty;
  score -= w.gamma * taxPenalty;
  score += w.delta * liquidityBonus;
  score += w.epsilon * goalBonus;
  score += w.zeta * horizonMatch;
  score -= w.eta * costPenalty;

  // ML confidence boost: dynamically boost instruments whose backend type
  // was predicted with high confidence by the ML model
  const mlConf = confScores[backendType] || 0;
  score += mlConf * PIPELINE_CONFIG.ML_BOOST_WEIGHT;

  return {
    ...inv,
    score,
    postTaxReturn: postTaxRate,
    backendType,
    nominalReturn: rate,
    effectiveYield: postTaxRate,
    taxNotes: postTax.notes,
    sharpeRatio: computeSharpe(postTaxRate, backendType),
  };
}

// ═══════════════════════════════════════════════════════════════════
// STAGE 3: RANKING
// ═══════════════════════════════════════════════════════════════════

/**
 * Sort scored instruments descending by score.
 */
function rankInstruments(scoredInstruments) {
  return [...scoredInstruments].sort((a, b) => b.score - a.score);
}

// ═══════════════════════════════════════════════════════════════════
// STAGE 4: DIVERSITY ENFORCEMENT
// ═══════════════════════════════════════════════════════════════════

/**
 * Enforce that top-N picks span at least MIN_ASSET_CLASSES distinct
 * asset classes. If diversity is insufficient, swap lower-ranked picks
 * with the next-best instrument from an unrepresented class.
 */
function enforceDiversity(ranked, topN, minClasses) {
  const result = [];
  const usedClasses = new Set();
  const usedIds = new Set();

  // First pass: take top-N greedily
  for (const inv of ranked) {
    if (result.length >= topN) break;
    if (usedIds.has(inv.id)) continue;
    result.push(inv);
    usedIds.add(inv.id);
    usedClasses.add(inv.assetClass || inv.category || inv.type);
  }

  // Second pass: if we lack diversity, swap the lowest-scored pick
  // with the best available from a missing class
  if (usedClasses.size < minClasses && ranked.length > topN) {
    const remaining = ranked.filter(inv => !usedIds.has(inv.id));
    for (const candidate of remaining) {
      const cls = candidate.assetClass || candidate.category || candidate.type;
      if (!usedClasses.has(cls)) {
        // Replace the lowest-scored item in result
        const lowestIdx = result.length - 1;
        const removed = result[lowestIdx];
        usedClasses.delete(removed.assetClass || removed.category || removed.type);
        result[lowestIdx] = candidate;
        usedIds.delete(removed.id);
        usedIds.add(candidate.id);
        usedClasses.add(cls);
        if (usedClasses.size >= minClasses) break;
      }
    }
  }

  return result;
}

// ═══════════════════════════════════════════════════════════════════
// HELPERS
// ═══════════════════════════════════════════════════════════════════

/**
 * Map a catalog instrument to its backend core type key
 * (one of the 19 keys in instrumentConstants.js).
 * Used for tax computation and Monte Carlo parameter lookup.
 */
const CATALOG_TO_BACKEND = {
  ppf: 'PPF', scss: 'SCSS', sukanya: 'SSY',
  rbi_bonds: 'RBI_Bond', sgb: 'SGB', nps: 'NPS',
  fd: 'FD', liquid_mf: 'Liquid_MF', debt_mf: 'Debt_MF',
  hybrid_mf: 'Hybrid_MF', index_mf: 'Index_MF',
  elss: 'ELSS', equity_mf: 'Equity_MF', etf: 'ETF',
  gold_etf: 'Gold', nifty_etf: 'ETF',
  midcap_mf: 'Midcap_MF', smallcap_mf: 'Smallcap_MF',
  arbitrage_mf: 'Arbitrage_MF', direct_equity: 'Equity_MF',
};

// Extended mappings for instruments that share a core type
const CATEGORY_TO_BACKEND = {
  'Government': 'RBI_Bond',
  'Gold': 'Gold',
  'Retirement': 'NPS',
  'Bank Deposits': 'FD',
  'Debt Mutual Funds': 'Debt_MF',
  'Equity Mutual Funds': 'Equity_MF',
  'ETFs': 'ETF',
  'REITs & InvITs': 'ETF',
  'Bonds & Debentures': 'Debt_MF',
  'Insurance-linked': 'Debt_MF',
  'Direct Equity': 'Equity_MF',
};

function resolveBackendType(inv) {
  // Direct ID mapping takes priority
  if (inv.id && CATALOG_TO_BACKEND[inv.id]) return CATALOG_TO_BACKEND[inv.id];

  // For specific fund variants, match by common prefix
  const id = (inv.id || '').toLowerCase();
  if (id.includes('fd') || id.includes('fixed_deposit')) return 'FD';
  if (id.includes('elss')) return 'ELSS';
  if (id.includes('liquid')) return 'Liquid_MF';
  if (id.includes('debt') || id.includes('corporate_bond') || id.includes('short_duration')) return 'Debt_MF';
  if (id.includes('hybrid') || id.includes('balanced')) return 'Hybrid_MF';
  if (id.includes('index') || id.includes('nifty_index')) return 'Index_MF';
  if (id.includes('midcap')) return 'Midcap_MF';
  if (id.includes('smallcap')) return 'Smallcap_MF';
  if (id.includes('gold')) return 'Gold';
  if (id.includes('arbitrage')) return 'Arbitrage_MF';
  if (id.includes('etf')) return 'ETF';
  if (id.includes('equity') || id.includes('flexi') || id.includes('bluechip') || id.includes('largecap')) return 'Equity_MF';

  // Category fallback
  if (inv.category && CATEGORY_TO_BACKEND[inv.category]) return CATEGORY_TO_BACKEND[inv.category];

  return 'Debt_MF'; // Safe default
}

function computeSharpe(postTaxReturn, backendType) {
  const vol = INSTRUMENT_PARAMS[backendType]?.volatility || 0.10;
  const postTaxDecimal = (postTaxReturn || 0) / 100;
  return vol > 0.001 ? parseFloat(((postTaxDecimal - RISK_FREE_RATE) / vol).toFixed(2)) : 0;
}

// ═══════════════════════════════════════════════════════════════════
// PUBLIC API — Main Pipeline Entry Point
// ═══════════════════════════════════════════════════════════════════

/**
 * Run the full recommendation pipeline.
 *
 * @param {Object} profile - User's FinancialProfile document (lean)
 * @param {Object} mlResult - ML prediction result from mlClient.js
 * @param {Object} [options] - Optional overrides
 * @param {number} [options.topN=5] - Number of recommendations to return
 * @param {number} [options.minAssetClasses=3] - Minimum asset class diversity
 * @returns {Object} { instruments: Array, confidenceScores: Object }
 */
export function runPipeline(profile, mlResult, options = {}) {
  const topN = options.topN || PIPELINE_CONFIG.TOP_N;
  const minClasses = options.minAssetClasses || PIPELINE_CONFIG.MIN_ASSET_CLASSES;

  // Normalise ML confidence scores
  const confScores = normaliseConfidenceScores(mlResult.confidence_scores || {});

  // Stage 1: Eligibility
  const eligible = filterEligible(investmentDatabase, profile);

  // Stage 2: Scoring
  const p = parseProfile(profile);
  const w = deriveWeights(p);
  const scored = eligible.map(inv => computeInstrumentScore(inv, p, w, confScores));

  // Stage 3: Ranking
  const ranked = rankInstruments(scored);

  // Stage 4: Diversity
  const topPicks = enforceDiversity(ranked, topN, minClasses);

  // Compute allocation weights from scores (normalized to sum to 1.0)
  const totalScore = topPicks.reduce((s, inv) => s + Math.max(0, inv.score), 0);
  const instruments = topPicks.map(inv => {
    const rawWeight = totalScore > 0 ? Math.max(0, inv.score) / totalScore : 1 / topPicks.length;
    return {
      name: inv.name,
      type: inv.backendType,
      instrumentId: inv.id,
      nominalReturn: inv.nominalReturn,
      postTaxReturn: inv.postTaxReturn,
      effectiveYield: inv.effectiveYield,
      taxNotes: inv.taxNotes,
      sharpeRatio: inv.sharpeRatio,
      expenseRatio: inv.expenseRatio || 0,
      riskLevel: INSTRUMENT_PARAMS[inv.backendType]?.riskLevel || inv.riskLabel || 'Medium',
      lockIn: inv.lockIn || 0,
      tags: INSTRUMENT_PARAMS[inv.backendType]?.tags || [],
      allocationWeight: parseFloat(rawWeight.toFixed(4)),
      score: parseFloat(inv.score.toFixed(2)),
    };
  });

  // Fix rounding: ensure weights sum to exactly 1.0
  const totalWeight = instruments.reduce((s, i) => s + i.allocationWeight, 0);
  if (totalWeight > 0 && instruments.length > 0) {
    instruments.forEach(i => { i.allocationWeight = parseFloat((i.allocationWeight / totalWeight).toFixed(4)); });
    const roundedSum = instruments.reduce((s, i) => s + i.allocationWeight, 0);
    const residual = parseFloat((1.0 - roundedSum).toFixed(4));
    if (residual !== 0) {
      const maxIdx = instruments.reduce((mi, w, i, arr) => w.allocationWeight > arr[mi].allocationWeight ? i : mi, 0);
      instruments[maxIdx].allocationWeight = parseFloat((instruments[maxIdx].allocationWeight + residual).toFixed(4));
    }
  }

  return { instruments, confidenceScores: confScores };
}

// ── Confidence score normalisation (reused from recommend.js) ────

const INSTRUMENT_KEY_MAP = {
  'Public_Provident_Fund': 'PPF',
  'Bank_FD':               'FD',
  'National_Pension':      'NPS',
  'RBI_Bond':              'RBI_Bond',
  'Sovereign_Gold_Bond':   'SGB',
  'Gold_ETF':              'Gold',
  'Nifty_Index':           'Index_MF',
  'Balanced_Advantage':    'Hybrid_MF',
};

function normaliseConfidenceScores(rawScores) {
  if (!rawScores || typeof rawScores !== 'object') return {};
  const normalised = {};
  for (const [key, value] of Object.entries(rawScores)) {
    if (typeof value !== 'number' || !isFinite(value)) continue;
    const mappedKey = INSTRUMENT_KEY_MAP[key] || key;
    normalised[mappedKey] = value;
  }
  return normalised;
}

