import Joi from 'joi';

// Allowed navigation routes whitelist
const ALLOWED_NAVIGATE_ROUTES = new Set([
  '/dashboard',
  '/profile',
  '/recommendations',
  '/tax-optimizer',
  '/tax',
  '/calculators',
  '/portfolio-rebalance',
  '/rebalancer',
  '/goals',
  '/stepup',
]);

const metricSchema = Joi.object({
  label: Joi.string().required().max(100),
  value: Joi.string().required().max(100),
  trend: Joi.string().valid('up', 'down', 'neutral').default('neutral'),
}).unknown(false);

const actionSchema = Joi.object({
  label: Joi.string().required().max(100),
  action: Joi.string().valid('navigate', 'modal', 'copy').required(),
  target: Joi.string().required().max(200).custom((value, helpers) => {
    if (!ALLOWED_NAVIGATE_ROUTES.has(value)) {
      return helpers.error('any.invalid');
    }
    return value;
  }, 'Whitelisted Route Validation'),
}).unknown(false);

const actionCardSchema = Joi.object({
  type: Joi.string().valid(
    'RECOMMENDATION',
    'TAX_SAVING',
    'SIP_CALCULATOR',
    'REBALANCE_ALERT',
    'GOAL_PROGRESS',
    'NAV_INSIGHT',
    'rebalance',
    'tax_save',
    'sip_stepup'
  ).required(),
  title: Joi.string().required().max(150),
  subtitle: Joi.string().max(200).optional(),
  description: Joi.string().max(500).optional(),
  metrics: Joi.array().items(metricSchema).min(1).max(5).required(),
  actions: Joi.array().items(actionSchema).min(1).max(3).required(),
  severity: Joi.string().valid('info', 'success', 'warning', 'danger').default('info'),
  priority: Joi.number().integer().min(1).max(10).optional(),
  insight: Joi.string().max(500).optional(),
}).unknown(false);

/**
 * Checks for prototype pollution attack keys in JSON objects.
 */
function containsPrototypePollution(jsonStr) {
  if (!jsonStr) return false;
  return /"__proto__"|"constructor"|"prototype"/i.test(jsonStr);
}

/**
 * Parses and validates ACTION_CARD JSON blocks embedded in chat response text.
 * Strips invalid card blocks without throwing errors or breaking text responses.
 *
 * @param {string} responseText
 * @returns {{ cleanedText: string, validCards: Array<object>, validationSummary: object }}
 */
export function validateAndSanitizeActionCards(responseText) {
  if (!responseText || typeof responseText !== 'string') {
    return { cleanedText: responseText || '', validCards: [], validationSummary: { totalFound: 0, validCount: 0, strippedCount: 0 } };
  }

  const cardRegex = /<<<ACTION_CARD>>>\s*([\s\S]*?)\s*<<<END_ACTION_CARD>>>/g;
  let match;
  const validCards = [];
  let strippedCount = 0;
  let totalFound = 0;

  let cleanedText = responseText;

  while ((match = cardRegex.exec(responseText)) !== null) {
    totalFound++;
    const rawJsonStr = match[1];
    const fullMatchBlock = match[0];

    if (containsPrototypePollution(rawJsonStr)) {
      console.warn('[ActionCardValidator] Prototype pollution attempt detected in card block, stripping.');
      cleanedText = cleanedText.replace(fullMatchBlock, '');
      strippedCount++;
      continue;
    }

    try {
      const parsedJson = JSON.parse(rawJsonStr);

      // Validate strictly against Joi schema
      const { error, value } = actionCardSchema.validate(parsedJson);

      if (error) {
        console.warn('[ActionCardValidator] Card validation failed, stripping card block:', error.details[0]?.message);
        cleanedText = cleanedText.replace(fullMatchBlock, '');
        strippedCount++;
      } else {
        validCards.push(value);
      }
    } catch (parseErr) {
      console.warn('[ActionCardValidator] Malformed JSON in ACTION_CARD block, stripping card block:', parseErr.message);
      cleanedText = cleanedText.replace(fullMatchBlock, '');
      strippedCount++;
    }
  }

  // Clean up any remaining unclosed <<<ACTION_CARD>>> tags if model output was truncated
  if (cleanedText.includes('<<<ACTION_CARD>>>') && !cleanedText.includes('<<<END_ACTION_CARD>>>')) {
    console.warn('[ActionCardValidator] Truncated unclosed ACTION_CARD detected and stripped.');
    cleanedText = cleanedText.replace(/<<<ACTION_CARD>>>[\s\S]*/, '').trim();
    strippedCount++;
  }

  return {
    cleanedText: cleanedText.trim(),
    validCards,
    validationSummary: {
      totalFound,
      validCount: validCards.length,
      strippedCount,
    },
  };
}

import { FinancialToolRegistry } from './financialToolRegistry.js';

/**
 * AI Tool Orchestrator & Dependency Graph Planner (Phase 1 & Phase 2)
 * Resolves tool execution DAGs, executes independent tools in parallel,
 * enforces typed input/output contract validation, and handles partial failures.
 */
export class AIToolOrchestrator {
  /**
   * Plans and executes a graph of tool calls requested by LLM intent.
   *
   * @param {Array<{ tool: string, arguments: object, dependsOn?: Array<string> }>} toolRequests
   * @param {object} context
   * @returns {Promise<{ toolResults: Array<object>, executionGraph: object, totalTimeMs: number }>}
   */
  static async orchestrate(toolRequests = [], context = {}) {
    const startTime = Date.now();
    const resultsMap = new Map();
    const executionGraph = {
      nodes: [],
      edges: [],
      status: 'SUCCESS',
    };

    if (!Array.isArray(toolRequests) || toolRequests.length === 0) {
      return {
        toolResults: [],
        executionGraph,
        totalTimeMs: Date.now() - startTime,
      };
    }

    // Step 1: Topological Sort / Dependency Resolution
    const pending = [...toolRequests];
    const maxPasses = pending.length + 2;
    let passes = 0;

    while (pending.length > 0 && passes < maxPasses) {
      passes++;
      const readyBatch = [];
      const remaining = [];

      for (const req of pending) {
        const deps = req.dependsOn || [];
        const allDepsSatisfied = deps.every(depName => resultsMap.has(depName) && resultsMap.get(depName).success);
        if (allDepsSatisfied) {
          readyBatch.push(req);
        } else {
          remaining.push(req);
        }
      }

      if (readyBatch.length === 0 && remaining.length > 0) {
        // Unresolvable cycle or missing dependency — break and execute remaining independently
        readyBatch.push(...remaining);
        remaining.length = 0;
      }

      // Step 2: Parallel execution of ready tool batch
      const batchPromises = readyBatch.map(req => this.executeWithRetry(req, context));
      const batchResults = await Promise.allSettled(batchPromises);

      batchResults.forEach((res, idx) => {
        const req = readyBatch[idx];
        const execResult = res.status === 'fulfilled'
          ? res.value
          : { tool: req.tool, success: false, error: res.reason?.message || 'Execution error', result: null, execution_time_ms: 0 };

        resultsMap.set(req.tool, execResult);
        executionGraph.nodes.push({
          tool: req.tool,
          arguments: req.arguments,
          success: execResult.success,
          result: execResult.result,
          error: execResult.error,
          executionTimeMs: execResult.execution_time_ms,
          provenance: 'WealthGenie_Financial_Engine_v2',
        });
      });

      pending.length = 0;
      pending.push(...remaining);
    }

    const finalResults = Array.from(resultsMap.values());
    const hasFailures = finalResults.some(r => !r.success);
    executionGraph.status = hasFailures ? 'PARTIAL_SUCCESS' : 'SUCCESS';

    return {
      toolResults: finalResults,
      executionGraph,
      totalTimeMs: Date.now() - startTime,
    };
  }

  /**
   * Executes a single tool request with retry budget (max 2 retries) and timeout (5000ms).
   */
  static async executeWithRetry(toolReq, context, maxRetries = 2) {
    const { tool, arguments: args } = toolReq;
    let attempt = 0;
    let lastError = null;

    while (attempt <= maxRetries) {
      attempt++;
      try {
        const timeoutPromise = new Promise((_, reject) =>
          setTimeout(() => reject(new Error(`Tool execution timeout (${tool})`)), 5000)
        );

        const execPromise = FinancialToolRegistry.executeTool(tool, args, context);
        const result = await Promise.race([execPromise, timeoutPromise]);

        if (result.success) {
          return { tool, arguments: args, ...result, retriesUsed: attempt - 1 };
        }
        lastError = result.error;
      } catch (err) {
        lastError = err.message;
      }
    }

    return {
      tool,
      arguments: args,
      success: false,
      error: lastError || 'Tool execution failed after retries',
      result: null,
      execution_time_ms: 0,
      retriesUsed: maxRetries,
    };
  }
}

import { sipFV, lumpSumFV } from './projectionEngine.js';
import { reverseSIP } from './monteCarloEngine.js';
import { computeTax } from './taxEngine.js';

/**
 * Independent Arithmetic Verification Engine
 * Analyzes LLM text output for numerical financial claims (SIP calculations, Lump Sum growth, Required SIP),
 * recomputes them using single-source-of-truth financial engines, and appends a correction if outside tolerance.
 *
 * @param {string} textText
 * @param {object} profile
 * @param {number} [tolerancePct=0.02] 2% tolerance threshold
 * @returns {{ verifiedText: string, verificationMetadata: object }}
 */
export function verifyAndCorrectArithmetic(textText, profile = {}, tolerancePct = 0.02) {
  if (!textText || typeof textText !== 'string') {
    return {
      verifiedText: textText || '',
      verificationMetadata: {
        verification_status: 'unverified',
        verified_fields: [],
        corrected_fields: [],
        verification_time_ms: 0,
      },
    };
  }

  const startTime = Date.now();
  let verifiedText = textText;
  const verifiedFields = [];
  const correctedFields = [];
  const correctionsToAppend = [];

  // Pattern 1: Monthly SIP calculation claim
  // e.g., "monthly SIP of ₹10,000 for 10 years at 12% annual return will yield ₹23.2 Lakhs"
  const sipRegex = /(?:monthly\s+SIP|investing|save[s]?)\s+of\s+₹?\s*([\d,]+)\s*(?:\/month|per\s+month)?\s+for\s+([\d.]+)\s*years?\s+at\s+([\d.]+)\s*%\s*(?:annual\s*return|CAGR)?(?:[^\n]*?(?:yield|grow|accumulate|reach|total[s]?)\s*(?:to\s*)?₹?\s*([\d,.]+)\s*(Lakhs?|Cr|Crores?)?)/gi;

  let match;
  while ((match = sipRegex.exec(textText)) !== null) {
    const rawMonthlySip = parseFloat(match[1].replace(/,/g, ''));
    const years = parseFloat(match[2]);
    const annualRatePct = parseFloat(match[3]);
    const claimedValueRaw = parseFloat(match[4].replace(/,/g, ''));
    const unit = match[5] ? match[5].toLowerCase() : null;

    if (Number.isFinite(rawMonthlySip) && Number.isFinite(years) && Number.isFinite(annualRatePct) && Number.isFinite(claimedValueRaw)) {
      let claimedValue = claimedValueRaw;
      if (unit && unit.startsWith('lakh')) {
        claimedValue *= 100000;
      } else if (unit && (unit.startsWith('cr') || unit.startsWith('crore'))) {
        claimedValue *= 10000000;
      }

      // Recompute using verified sipFV engine formula (single source of truth)
      const annualRate = annualRatePct / 100;
      const expectedFV = sipFV(rawMonthlySip, annualRate, years);

      const diffRatio = Math.abs(claimedValue - expectedFV) / Math.max(expectedFV, 1);

      if (diffRatio <= tolerancePct) {
        verifiedFields.push({
          field: 'SIP_FUTURE_VALUE',
          claimed: claimedValue,
          verified: expectedFV,
          withinTolerance: true,
        });
      } else {
        const formattedExpected = formatIndianCurrency(expectedFV);
        const formattedClaimed = formatIndianCurrency(claimedValue);

        correctedFields.push({
          field: 'SIP_FUTURE_VALUE',
          claimed: claimedValue,
          verified: expectedFV,
          diffRatio,
        });

        correctionsToAppend.push(
          `*Verified Financial Calculation:* A monthly SIP of ₹${rawMonthlySip.toLocaleString('en-IN')} at ${annualRatePct}% p.a. over ${years} years actually yields ${formattedExpected} rather than ${formattedClaimed}.`
        );
      }
    }
  }

  // Pattern 2: Lump Sum Compound Interest claim
  // e.g., "lump sum of ₹1,000,000 for 5 years at 10% annual return will grow to ₹1,610,510"
  const lumpSumRegex = /(?:lump\s*sum|one-time\s+investment)\s+of\s+₹?\s*([\d,]+)\s+for\s+([\d.]+)\s*years?\s+at\s+([\d.]+)\s*%\s*(?:annual\s*return|CAGR)?(?:[^\n]*?(?:grow|accumulate|reach|total[s]?)\s*(?:to\s*)?₹?\s*([\d,.]+)\s*(Lakhs?|Cr|Crores?)?)/gi;

  while ((match = lumpSumRegex.exec(textText)) !== null) {
    const principal = parseFloat(match[1].replace(/,/g, ''));
    const years = parseFloat(match[2]);
    const annualRatePct = parseFloat(match[3]);
    const claimedValueRaw = parseFloat(match[4].replace(/,/g, ''));
    const unit = match[5] ? match[5].toLowerCase() : null;

    if (Number.isFinite(principal) && Number.isFinite(years) && Number.isFinite(annualRatePct) && Number.isFinite(claimedValueRaw)) {
      let claimedValue = claimedValueRaw;
      if (unit && unit.startsWith('lakh')) claimedValue *= 100000;
      else if (unit && (unit.startsWith('cr') || unit.startsWith('crore'))) claimedValue *= 10000000;

      // Recompute using verified lumpSumFV engine formula (single source of truth)
      const expectedFV = lumpSumFV(principal, annualRatePct / 100, years);
      const diffRatio = Math.abs(claimedValue - expectedFV) / Math.max(expectedFV, 1);

      if (diffRatio <= tolerancePct) {
        verifiedFields.push({ field: 'LUMP_SUM_FUTURE_VALUE', claimed: claimedValue, verified: expectedFV, withinTolerance: true });
      } else {
        const formattedExpected = formatIndianCurrency(expectedFV);
        const formattedClaimed = formatIndianCurrency(claimedValue);
        correctedFields.push({ field: 'LUMP_SUM_FUTURE_VALUE', claimed: claimedValue, verified: expectedFV, diffRatio });
        correctionsToAppend.push(
          `*Verified Financial Calculation:* A lump sum of ₹${principal.toLocaleString('en-IN')} at ${annualRatePct}% p.a. over ${years} years grows to ${formattedExpected} rather than ${formattedClaimed}.`
        );
      }
    }
  }

  // Appending visible corrections if any field failed tolerance
  if (correctionsToAppend.length > 0) {
    verifiedText = verifiedText.trim() + '\n\n' + correctionsToAppend.join('\n');
  }

  const status = correctedFields.length > 0
    ? 'corrected'
    : (verifiedFields.length > 0 ? 'verified' : 'unverified');

  const verificationMetadata = {
    verification_status: status,
    verified_fields: verifiedFields,
    corrected_fields: correctedFields,
    verification_time_ms: Date.now() - startTime,
  };

  return { verifiedText, verificationMetadata };
}

function formatIndianCurrency(val) {
  if (val >= 10000000) {
    return `₹${(val / 10000000).toFixed(2)} Cr`;
  }
  if (val >= 100000) {
    return `₹${(val / 100000).toFixed(2)} Lakhs`;
  }
  return `₹${Math.round(val).toLocaleString('en-IN')}`;
}

/**
 * Genie Chat Service — Dual-provider (Gemini + Groq fallback) v3 Platform Engine
 * Rate limiting, context assembly, API calls, conversation persistence, state machine,
 * provider abstraction, tool orchestrator, explainability, trace graph.
 */
import axios from 'axios';
import { getCache, setCache, redisClient, redisAvailable } from '../config/redis.js';
import { buildSystemPrompt } from './genieChatSystemPrompt.js';
import { createError } from '../middleware/errorHandler.js';
import ConversationHistory from '../models/ConversationHistory.js';
import FinancialProfile from '../models/FinancialProfile.js';
import Recommendation from '../models/Recommendation.js';
import Goal from '../models/Goal.js';
import User from '../models/User.js';

import { validateAndSanitizeActionCards } from './actionCardValidator.js';
import { verifyAndCorrectArithmetic } from './arithmeticVerifier.js';
import { inspectPromptSecurity } from './promptSecurity.js';
import { FinancialToolRegistry } from './financialToolRegistry.js';
import { validateAndSanitizeStructuredResponse } from './structuredResponseProtocol.js';
import { ImmutableSecurityPipeline } from './immutableSecurityPipeline.js';
import { PrometheusMetrics } from './metricsCollector.js';
import { ProviderManager } from './providerAbstraction.js';
import { AIToolOrchestrator } from './aiToolOrchestrator.js';
import { ConversationStateMachine, CONVERSATION_STATES } from './conversationStateMachine.js';
import { LayeredMemoryManager } from './layeredMemoryManager.js';
import { ExplainabilityEngine } from './explainabilityEngine.js';
import { ToolTraceGraph, promptVersion, policyVersion } from './toolTraceGraph.js';

const CHAT_RATE_LIMIT = 30;
const HISTORY_WINDOW = 20;
const MAX_OUTPUT_TOKENS = 4096;
const SYSTEM_PROMPT_TTL = 1800;

// STATELESS: Rate limits are stored strictly in Redis. No in-memory Map fallback.
async function checkRateLimit(userId) {
  const key = `chat:ratelimit:${userId}`;
  if (redisClient && redisAvailable) {
    try {
      const count = await redisClient.incr(key);
      if (count === 1) await redisClient.expire(key, 3600);
      if (count > CHAT_RATE_LIMIT) {
        const ttl = await redisClient.ttl(key);
        return { allowed: false, count, ttl };
      }
      return { allowed: true, count };
    } catch (_) { /* fallthrough */ }
  }
  // Without Redis, allow request to avoid in-memory state divergence across instances
  return { allowed: true, count: 1 };
}

export async function processChat({ userId, user, message, sessionId }) {
  const rateCheck = await checkRateLimit(userId);
  if (!rateCheck.allowed) {
    throw createError(429, `Rate limit for user ${userId}`, `Chat limit reached (${CHAT_RATE_LIMIT}/hour). Resets in ${Math.ceil(rateCheck.ttl / 60)} minutes.`);
  }

  const profile = await FinancialProfile.findOne({ userId }).sort({ createdAt: -1 }).lean();
  if (!profile) {
    return {
      version: '3.0',
      response: "I don't have your financial profile yet. Please complete the profile setup on the home page so I can give you personalised advice.",
      session_id: sessionId, grounded: false,
      messages_this_hour: rateCheck.count, rate_limit_remaining: CHAT_RATE_LIMIT - rateCheck.count,
    };
  }

  // Phase 5: Multi-layer Immutable Security Pipeline
  const securityContext = ImmutableSecurityPipeline.processInput(message, profile);
  if (securityContext.isInjection) {
    PrometheusMetrics.inc('prompt_injection_attempts_total');
  }

  const recommendation = await Recommendation.findOne({ userId, profileId: profile._id }).sort({ generatedAt: -1 }).lean();
  const goals = await Goal.find({ userId }).sort({ createdAt: -1 }).lean();

  const fullUser = await User.findById(userId).lean() || { name: user.email, email: user.email };

  let conversation = await ConversationHistory.findOne({ userId, session_id: sessionId, is_active: true });
  if (!conversation) {
    conversation = new ConversationHistory({ userId, profileId: profile._id, session_id: sessionId, messages: [] });
  }

  // Phase 4 & Phase 5: Layered Long-Term Memory & Context Retrieval
  const retrievedMemory = LayeredMemoryManager.buildRetrievedContext(message, profile, goals, recommendation, conversation.messages);
  const formattedMemoryContext = LayeredMemoryManager.formatForPrompt(retrievedMemory);

  const promptCacheKey = `chat:sysprompt_v3:${userId}:${profile._id}:${goals.length}:${recommendation?.generatedAt || 'none'}`;
  let baseSystemPrompt = await getCache(promptCacheKey);
  if (!baseSystemPrompt) {
    let marketData = null;
    try { const cached = await getCache('index:stats:^NSEI'); marketData = cached ? { nifty: cached } : null; } catch (err) { console.warn('[GeminiChatService] Redis cache read failed:', err.message); }
    baseSystemPrompt = buildSystemPrompt(fullUser, profile, recommendation, marketData, goals);
    await setCache(promptCacheKey, baseSystemPrompt, SYSTEM_PROMPT_TTL);
  }

  const systemPrompt = `${baseSystemPrompt}\n\n${formattedMemoryContext}`;

  const recentHistory = conversation.messages.slice(-HISTORY_WINDOW).map(m => ({ role: m.role, parts: [{ text: m.content }] }));
  recentHistory.push({ role: 'user', parts: [{ text: securityContext.sanitizedMessage }] });

  const startTime = Date.now();

  // Phase 9: Provider Abstraction Layer & Resilient Execution
  let result = await ProviderManager.gemini.generate({ systemPrompt, recentHistory, maxTokens: MAX_OUTPUT_TOKENS });
  if (!result) {
    console.info('[Chat] Gemini adapter unavailable/failed, falling back to Groq adapter...');
    result = await ProviderManager.groq.generate({ systemPrompt, recentHistory, maxTokens: MAX_OUTPUT_TOKENS });
  }

  const latencyMs = Date.now() - startTime;
  let rawResponseText = '';
  let tokensUsed = 0;
  let provider = '';
  let wasCompleted = true;
  let isFallback = false;

  if (!result) {
    console.info('[Chat] Dual providers failed, executing local fallback adapter...');
    isFallback = true;
    const fallbackText = generateLocalFallbackResponse(fullUser, profile, goals, message);
    result = await ProviderManager.local.generate({ fallbackText });
  }

  rawResponseText = result.text;
  tokensUsed = result.tokensUsed;
  provider = result.provider;
  wasCompleted = result.wasCompleted;

  PrometheusMetrics.recordLatency(provider, latencyMs);

  // Phase 1: Structured V2.0 Contract Protocol & Sanitization
  const v2Protocol = validateAndSanitizeStructuredResponse(rawResponseText);
  let responseText = v2Protocol.answer || rawResponseText;

  // Phase 1 & Phase 2: AI Tool Orchestrator DAG Resolution & Execution
  const orchestration = await AIToolOrchestrator.orchestrate(v2Protocol.tool_calls, { profile, user: fullUser });
  const toolResults = orchestration.toolResults;

  // Phase 2: Server-Side ACTION_CARD Validation
  const { cleanedText, validCards, validationSummary } = validateAndSanitizeActionCards(responseText);
  responseText = cleanedText;

  // Phase 3: Independent Arithmetic Verification
  const { verifiedText, verificationMetadata } = verifyAndCorrectArithmetic(responseText, profile);
  responseText = verifiedText;

  // Phase 5: Enforce Regulatory Compliance
  responseText = ImmutableSecurityPipeline.enforceCompliance(responseText);

  // Phase 3: Conversation State Machine Transition
  const stateTransition = ConversationStateMachine.transition(CONVERSATION_STATES.IDLE, {
    userMessage: message,
    hasTools: v2Protocol.tool_calls?.length > 0,
    toolResults,
    isFallback,
  });

  // Phase 6: Explainability Engine Metadata Generation
  const explanationMetadata = ExplainabilityEngine.generateExplanation(profile, toolResults, verificationMetadata);

  // Phase 7 & Phase 16: Tool Trace Graph & Governance
  const traceGraph = ToolTraceGraph.buildTraceGraph({
    sessionId,
    userId,
    userMessage: message,
    stateTransition,
    provider,
    retrievedContext: retrievedMemory,
    executionGraph: orchestration.executionGraph,
    verificationMetadata,
    explanationMetadata,
    responseText,
  });

  console.info(`[Chat] [${provider}] State: ${stateTransition.nextState}. Response: ${responseText.length} chars. Tools: ${toolResults.length}. Verif: ${verificationMetadata.verification_status}.`);

  // Phase 7 & Phase 16: Complete Multi-Stage Governance Audit Persistence
  const auditMetadata = {
    original_llm_response: rawResponseText,
    validated_v2_protocol: v2Protocol,
    tool_requests: v2Protocol.tool_calls,
    tool_outputs: toolResults,
    execution_graph: orchestration.executionGraph,
    corrections_applied: verificationMetadata.corrected_fields,
    final_response: responseText,
    provider,
    state: stateTransition.nextState,
    explainability: explanationMetadata,
    governance: traceGraph.governance,
    tokens_used: tokensUsed,
    latency_ms: latencyMs,
    grounded_on_profile: true,
    disclaimer_appended: true,
    action_cards: validCards,
    action_cards_summary: validationSummary,
    arithmetic_verification: verificationMetadata,
    timestamp: new Date().toISOString(),
  };

  conversation.messages.push({ role: 'user', content: message, metadata: { grounded_on_profile: true, prompt_injection_detected: securityContext.isInjection } });
  conversation.messages.push({
    role: 'model',
    content: responseText,
    metadata: auditMetadata,
  });
  await conversation.save();

  return {
    version: '3.0',
    response: responseText,
    session_id: sessionId,
    latency_ms: latencyMs,
    tokens_used: tokensUsed,
    messages_this_hour: rateCheck.count,
    rate_limit_remaining: CHAT_RATE_LIMIT - rateCheck.count,
    grounded: true,
    provider,
    state: stateTransition.nextState,
    tool_calls: v2Protocol.tool_calls,
    tool_results: toolResults,
    action_cards: validCards,
    verification: verificationMetadata,
    explainability: explanationMetadata,
    governance: traceGraph.governance,
    audit: auditMetadata,
  };
}

