};

/**
 * WealthGenie Risk Profiler
 * Categorizes users into risk buckets based on age + annual income + investment horizon + financial ratios.
 *
 * =========================================================================
 * 📘 BEGINNER NOTE: WHAT IS COMPOSITE RISK SCORING?
 * =========================================================================
 * Risk capacity is not just about how you "feel" about the stock market. It is
 * a mathematical combination of your ability to take risk (financial strength)
 * and your timeline (investment horizon).
 * 
 * WealthGenie uses a 3-Factor Composite Scoring Model (ranging from 0 to 100 points):
 * 
 * 1. Age (0–40 points): Younger investors have more decades ahead of them. If the 
 *    market crashes tomorrow, they have time to wait for a recovery before needing
 *    the money. Thus: Younger = Higher Risk Score.
 * 
 * 2. Annual Income (0–40 points): Higher earners have a larger financial cushion.
 *    If an emergency occurs, they can cover it from their current cash flow rather than
 *    being forced to sell investments at a loss. Thus: Higher Income = Higher Risk Score.
 * 
 * 3. Investment Horizon (0–20 points): How long will the money stay invested? 
 *    If you need the money in 2 years, you cannot afford a market crash (low risk). 
 *    If you need it in 20 years, short-term crashes don't matter because the market
 *    historically trends upwards over long periods. Thus: Longer Horizon = Higher Risk Score.
 * 
 * We also subtract penalties for high debt levels or dependents, giving us a highly
 * personalized, mathematically balanced risk score. This avoids the "cliff-edge"
 * problem where a ₹1 income difference shifts you from Moderate to Conservative.
 */

const RISK_PROFILES = {
  Aggressive: {
    category: 'Aggressive',
    description: 'High risk tolerance — suited for equity-heavy portfolios with long-term growth focus. Can withstand 30-40% interim drawdowns.',
    recommendedEquityAllocation: 80,
  },
  'Moderate-Aggressive': {
    category: 'Moderate-Aggressive',
    description: 'Above-average risk tolerance — balanced toward equity with some debt allocation for stability. Growth-oriented with moderate volatility acceptance.',
    recommendedEquityAllocation: 65,
  },
  Moderate: {
    category: 'Moderate',
    description: 'Balanced risk approach — equal weight to equity and debt instruments. Seeks steady growth with controlled downside.',
    recommendedEquityAllocation: 50,
  },
  'Conservative-Moderate': {
    category: 'Conservative-Moderate',
    description: 'Below-average risk tolerance — debt-heavy portfolio with limited equity exposure. Prioritizes capital preservation with modest growth.',
    recommendedEquityAllocation: 35,
  },
  Conservative: {
    category: 'Conservative',
    description: 'Low risk tolerance — focused on capital preservation through government securities, FDs, and debt funds. Minimal equity exposure.',
    recommendedEquityAllocation: 20,
  },
};

/**
 * Compute age-based risk score (0–40).
 * Linear decay: age 18 → 40 points, age 70 → 0 points.
 * Clamped to [0, 40].
 *
 * @param {number} age
 * @returns {number}
 */
function ageScore(age) {
  // Linear: score = 40 × (1 - (age - 18) / 52)
  // At age 18: 40, at age 44: 20, at age 70: 0
  const raw = 40 * (1 - Math.max(0, age - 18) / 52);
  return Math.max(0, Math.min(40, raw));
}

/**
 * Compute income-based risk score (0–40).
 * Logarithmic scale — diminishing returns above ₹20L.
 * Clamped to [0, 40].
 *
 * @param {number} annualIncome - Gross annual income in ₹
 * @returns {number}
 */
function incomeScore(annualIncome) {
  if (annualIncome <= 0) return 0;
  // Log scale: ~8 at ₹3L, ~20 at ₹6L, ~28 at ₹12L, ~34 at ₹25L, ~40 at ₹50L+
  const raw = 40 * Math.min(1, Math.log10(annualIncome / 100000) / 1.7);
  return Math.max(0, Math.min(40, raw));
}

/**
 * Compute investment-horizon-based risk score (0–20).
 * Longer horizons allow more volatility tolerance since
 * short-term drawdowns are smoothed over time.
 * Clamped to [0, 20].
 *
 * @param {number} horizonYears - Investment horizon in years
 * @returns {number}
 */
function horizonScore(horizonYears) {
  if (horizonYears <= 0) return 0;
  // Linear: 1yr → 2pts, 5yr → 7pts, 10yr → 12pts, 20yr → 18pts, 30yr+ → 20pts
  const raw = 20 * Math.min(1, horizonYears / 30);
  return Math.max(0, Math.min(20, raw));
}

/**
 * Determine risk profile based on age, annual income, and investment horizon
 * using composite scoring.
 *
 * Score ranges (total 0–100 from 40+40+20):
 *   80–100 → Aggressive
 *   60–79  → Moderate-Aggressive
 *   40–59  → Moderate
 *   20–39  → Conservative-Moderate
 *   0–19   → Conservative
 *
 * @param {number} age - User's age in years
 * @param {number} annualIncome - User's gross annual income in ₹
 * @param {number} [investmentHorizon=15] - Investment horizon in years (optional)
 * @returns {{ category, description, recommendedEquityAllocation, riskScore }}
 */
export function getRiskProfile(
  age,
  annualIncome,
  investmentHorizon = 15,
  experienceYears = 0,
  dependents = 0,
  monthlySavings = null,
  monthlyDebtPayment = 0
) {
  // Input guards
  const safeAge = Math.max(18, Math.min(80, Number(age) || 30));
  const safeIncome = Math.max(0, Number(annualIncome) || 0);
  const safeHorizon = Math.max(1, Math.min(40, Number(investmentHorizon) || 15));
  const safeExperience = Math.max(0, Number(experienceYears) || 0);
  const safeDependents = Math.max(0, Number(dependents) || 0);

  // Calculate components
  const scoreAge = ageScore(safeAge);
  const scoreIncome = incomeScore(safeIncome);
  const scoreHorizon = horizonScore(safeHorizon);
  const scoreExperience = Math.min(10, safeExperience * 2);
  const penaltyDependents = Math.min(10, safeDependents * 2);

  // Savings-to-income ratio penalty: max 15 points
  let penaltySavings = 0;
  if (monthlySavings !== null && monthlySavings !== undefined) {
    const safeSavings = Math.max(0, Number(monthlySavings) || 0);
    const savingsRatio = safeIncome > 0 ? (safeSavings * 12) / safeIncome : 0.15;
    if (savingsRatio < 0.15) {
      penaltySavings = Math.min(15, 15 * (1 - savingsRatio / 0.15));
    }
  }

  // Debt-to-income ratio penalty: max 15 points (triggered if EMI > 30% of gross monthly income)
  let penaltyDebt = 0;
  if (monthlyDebtPayment !== null && monthlyDebtPayment !== undefined) {
    const safeDebt = Math.max(0, Number(monthlyDebtPayment) || 0);
    const debtRatio = safeIncome > 0 ? (safeDebt * 12) / safeIncome : 0;
    if (debtRatio > 0.30) {
      penaltyDebt = Math.min(15, (debtRatio - 0.30) * 50);
    }
  }

  const rawScore = scoreAge + scoreIncome + scoreHorizon + scoreExperience - penaltyDependents - penaltySavings - penaltyDebt;
  const score = Math.max(0, Math.min(100, rawScore));

  let profileKey;
  if (score >= 80)      profileKey = 'Aggressive';
  else if (score >= 60) profileKey = 'Moderate-Aggressive';
  else if (score >= 40) profileKey = 'Moderate';
  else if (score >= 20) profileKey = 'Conservative-Moderate';
  else                  profileKey = 'Conservative';

  // Smooth recommended equity allocation: 20% to 80% (slope 0.75 points per risk score unit)
  const smoothAllocation = 20 + Math.max(0, Math.min(80, score - 10)) * 0.75;
  const recommendedAllocation = Math.round(smoothAllocation);

  return {
    ...RISK_PROFILES[profileKey],
    recommendedEquityAllocation: recommendedAllocation,
    riskScore: Math.round(score),
  };
}

/**
 * Encode risk category to numeric score for ML features.
 *
 * @param {string} category
 * @returns {number} 0-4 scale
 */
export function encodeRiskCategory(category) {
  const map = {
    'Conservative': 0,
    'Conservative-Moderate': 1,
    'Moderate': 2,
    'Moderate-Aggressive': 3,
    'Aggressive': 4,
  };
  return map[category] ?? 2;
}

import Joi from 'joi';

const toolCallSchema = Joi.object({
  tool: Joi.string().required().max(100),
  arguments: Joi.object().default({}),
  id: Joi.string().max(100).optional(),
}).unknown(true);

const actionCardRefSchema = Joi.object({
  type: Joi.string().required(),
  title: Joi.string().required().max(150),
  subtitle: Joi.string().max(200).optional(),
  description: Joi.string().max(500).optional(),
  metrics: Joi.array().items(Joi.object().unknown(true)).optional(),
  actions: Joi.array().items(Joi.object().unknown(true)).optional(),
  severity: Joi.string().valid('info', 'success', 'warning', 'danger').default('info'),
  priority: Joi.number().optional(),
  insight: Joi.string().max(500).optional(),
}).unknown(true);

export const structuredResponseSchema = Joi.object({
  version: Joi.string().valid('2.0', '1.0').default('2.0'),
  answer: Joi.string().allow('').default(''),
  tool_calls: Joi.array().items(toolCallSchema).default([]),
  action_cards: Joi.array().items(actionCardRefSchema).default([]),
  citations: Joi.array().items(Joi.string()).default([]),
  metadata: Joi.object().default({}),
}).unknown(true);

/**
 * Validates, normalizes, and sanitizes LLM responses into the Version 2.0 Structured Protocol.
 *
 * @param {string|object} rawResponse
 * @returns {{ version: string, answer: string, tool_calls: Array<object>, action_cards: Array<object>, citations: Array<string>, metadata: object }}
 */
export function validateAndSanitizeStructuredResponse(rawResponse) {
  let parsedObject = null;

  if (typeof rawResponse === 'object' && rawResponse !== null) {
    parsedObject = rawResponse;
  } else if (typeof rawResponse === 'string') {
    const trimmed = rawResponse.trim();
    // Check if entire output is a JSON block
    if ((trimmed.startsWith('{') && trimmed.endsWith('}')) || trimmed.includes('```json')) {
      try {
        let jsonStr = trimmed;
        if (jsonStr.includes('```json')) {
          jsonStr = jsonStr.split('```json')[1].split('```')[0].trim();
        }
        parsedObject = JSON.parse(jsonStr);
      } catch (_) {
        /* Not valid standalone JSON; treat as text answer */
      }
    }
  }

  // If no structured object was parsed, construct standard v2.0 response wrapper
  if (!parsedObject || typeof parsedObject !== 'object') {
    return {
      version: '2.0',
      answer: typeof rawResponse === 'string' ? rawResponse : '',
      tool_calls: [],
      action_cards: [],
      citations: [],
      metadata: { format: 'unstructured_text_fallback' },
    };
  }

  // Validate against Joi schema
  const { error, value } = structuredResponseSchema.validate(parsedObject, { stripUnknown: false });

  if (error) {
    console.warn('[StructuredResponseProtocol] Schema validation warning:', error.details[0]?.message);
    return {
      version: '2.0',
      answer: typeof parsedObject.answer === 'string' ? parsedObject.answer : String(rawResponse),
      tool_calls: Array.isArray(parsedObject.tool_calls) ? parsedObject.tool_calls.filter(t => t && t.tool) : [],
      action_cards: Array.isArray(parsedObject.action_cards) ? parsedObject.action_cards : [],
      citations: Array.isArray(parsedObject.citations) ? parsedObject.citations : [],
      metadata: { format: 'partial_sanitized_fallback' },
    };
  }

  return {
    version: '2.0',
    answer: value.answer || '',
    tool_calls: value.tool_calls || [],
    action_cards: value.action_cards || [],
    citations: value.citations || [],
    metadata: value.metadata || {},
  };
}

import { CESS_RATE } from './instrumentConstants.js';
/**
 * Dynamically computes India's current fiscal year (April 1st to March 31st).
 * @returns {string} e.g. "FY2026-27"
 */
export function getCurrentFiscalYear() {
    const now = new Date();
    const year = now.getFullYear();
    // India's fiscal year starts in April (month index 3)
    const isAprilOrLater = now.getMonth() >= 3;
    const startYear = isAprilOrLater ? year : year - 1;
    const endYear = startYear + 1;
    return `FY${startYear}-${endYear.toString().slice(-2)}`;
}
export const CURRENT_FY = getCurrentFiscalYear();
const defineSlabs = (slabs) => Object.freeze(slabs.map(slab => Object.freeze({ ...slab })));
const STANDARD_NEW_SLABS = defineSlabs([
    { min: 0, max: 400000, rate: 0 },
    { min: 400000, max: 800000, rate: 0.05 },
    { min: 800000, max: 1200000, rate: 0.10 },
    { min: 1200000, max: 1600000, rate: 0.15 },
    { min: 1600000, max: 2000000, rate: 0.20 },
    { min: 2000000, max: 2400000, rate: 0.25 },
    { min: 2400000, max: Infinity, rate: 0.30 },
]);
const STANDARD_OLD_SLABS = defineSlabs([
    { min: 0, max: 250000, rate: 0 },
    { min: 250000, max: 500000, rate: 0.05 },
    { min: 500000, max: 1000000, rate: 0.20 },
    { min: 1000000, max: Infinity, rate: 0.30 },
]);

export const TAX_SLABS_BY_FY = Object.freeze({
    'FY2025-26': Object.freeze({
        verified: true, // Confirmed against Finance Act 2023 / Union Budget 2024.
        new: STANDARD_NEW_SLABS,
        old: STANDARD_OLD_SLABS,
    }),
    'FY2026-27': Object.freeze({
        // FY2026-27: Union Budget 2025 confirmed same slab rates as FY2025-26. verified=true.
        verified: true,
        new: STANDARD_NEW_SLABS,
        old: STANDARD_OLD_SLABS,
    }),
});
export function getTaxSlabsForFY(fiscalYear = CURRENT_FY) {
    return TAX_SLABS_BY_FY[fiscalYear] || TAX_SLABS_BY_FY[CURRENT_FY];
}
/**
 * Check whether the tax slabs for a given fiscal year have been verified
 * against an official gazette/Union Budget source.
 */
export function isFYVerified(fiscalYear = CURRENT_FY) {
    const entry = TAX_SLABS_BY_FY[fiscalYear];
    return entry ? entry.verified === true : false;
}
function getRegimeSlabs(regime, fiscalYear = CURRENT_FY) {
    const slabs = getTaxSlabsForFY(fiscalYear);
    return regime === 'old' ? slabs.old : slabs.new;
}
/**
 * Calculate tax from slab structure.
 */
function calculateFromSlabs(taxableIncome, slabs) {
    let tax = 0;
    for (const slab of slabs) {
        if (taxableIncome <= slab.min)
            break;
        const taxableInSlab = Math.min(taxableIncome, slab.max) - slab.min;
        tax += taxableInSlab * slab.rate;
    }
    return tax;
}
/**
 * Compute surcharge on base tax for high-income individuals.
 */
function computeSurcharge(taxBeforeSurcharge, taxableIncome, regime) {
    if (taxableIncome <= 5000000)
        return 0; // Below ₹50L: no surcharge
    let surchargeRate = 0;
    if (regime === 'new') {
        if (taxableIncome <= 10000000)
            surchargeRate = 0.10;
        else if (taxableIncome <= 20000000)
            surchargeRate = 0.15;
        else
            surchargeRate = 0.25;
    }
    else {
        // Old regime
        if (taxableIncome <= 10000000)
            surchargeRate = 0.10;
        else if (taxableIncome <= 20000000)
            surchargeRate = 0.15;
        else if (taxableIncome <= 50000000)
            surchargeRate = 0.25;
        else
            surchargeRate = 0.37;
    }
    return taxBeforeSurcharge * surchargeRate;
}
/**
 * Compute surcharge WITH marginal relief.
 */
function computeMarginalRelief(baseTax, surcharge, taxableIncome, regime, fiscalYear = CURRENT_FY) {
    if (taxableIncome <= 5000000)
        return 0;
    const SURCHARGE_THRESHOLDS = regime === 'new'
        ? [5000000, 10000000, 20000000]
        : [5000000, 10000000, 20000000, 50000000];
    // Find the highest active threshold strictly below the taxable income
    let threshold = 5000000;
    for (const t of SURCHARGE_THRESHOLDS) {
        if (taxableIncome > t) {
            threshold = t;
        }
    }
    const slabs = getRegimeSlabs(regime, fiscalYear);
    const baseTaxAtThreshold = calculateFromSlabs(threshold, slabs);
    // Surcharge rate AT exactly the threshold limit
    let thresholdSurchargeRate = 0;
    if (threshold === 10000000) {
        thresholdSurchargeRate = 0.10;
    }
    else if (threshold === 20000000) {
        thresholdSurchargeRate = 0.15;
    }
    else if (threshold === 50000000 && regime === 'old') {
        thresholdSurchargeRate = 0.25;
    }
    const taxAtThreshold = baseTaxAtThreshold * (1 + thresholdSurchargeRate);
    // Total tax at actual income
    const totalActual = baseTax + surcharge;
    // Income gain above threshold
    const incomeGain = taxableIncome - threshold;
    // Relief: tax should not exceed tax-at-threshold + income-gain
    const maxAllowedTax = taxAtThreshold + incomeGain;
    const marginalRelief = totalActual > maxAllowedTax ? totalActual - maxAllowedTax : 0;
    return Math.round(marginalRelief);
}
/**
 * Helper to compute allowed standard and section-wise deductions and taxable income.
 */
export function calculateTaxableIncome(annualIncome, regime = 'new', deductions = {}, incomeSource = 'salary') {
    let standardDeduction = 0;
    if (incomeSource === 'salary' || incomeSource === 'pension') {
        standardDeduction = regime === 'new' ? 75000 : 50000;
    }
    else if (incomeSource === 'family_pension') {
        standardDeduction = Math.min(annualIncome / 3, 15000);
    }
    // Section 80CCD(2) - Employer NPS Contribution (available under both regimes)
    const basicSalary = deductions.basicSalary || (annualIncome * 0.5);
    const isGovtEmployee = deductions.isGovtEmployee === true;
    const nps80CCD2LimitPercent = isGovtEmployee ? 0.14 : 0.10;
    const max80CCD2 = basicSalary * nps80CCD2LimitPercent;
    const nps80CCD2 = Math.min(deductions.nps80CCD2 || 0, max80CCD2);
    const section80C = Math.min(deductions.section80C || 0, 150000);
    const nps80CCD1B = Math.min(deductions.nps80CCD1B || deductions.section80CCD || 0, 50000);
    // Section 80D Granular Self vs. Parents
    const age = deductions.age || 30;
    const selfSenior = age >= 60 || deductions.self_senior === true;
    const parentsSenior = deductions.parents_senior === true;
    const max80D_self = selfSenior ? 50000 : 25000;
    const max80D_parents = parentsSenior ? 50000 : 25000;
    let allowed80D = 0;
    if (deductions.section80D_self !== undefined || deductions.section80D_parents !== undefined) {
        const allowed80D_self = Math.min(deductions.section80D_self || 0, max80D_self);
        const allowed80D_parents = Math.min(deductions.section80D_parents || 0, max80D_parents);
        allowed80D = allowed80D_self + allowed80D_parents;
    }
    else {
        allowed80D = Math.min(deductions.section80D || 0, 100000);
    }
    const hra = deductions.hra || 0;
    const homeLoanInterest = Math.min(deductions.homeLoanInterest || 0, 200000);
    const section80EEA = Math.min(deductions.section80EEA || 0, 150000);
    const otherDeductions = deductions.other || 0;
    const savingsInterest = deductions.savingsInterest || 0;
    let section80TTA = deductions.section80TTA || 0;
    let section80TTB = deductions.section80TTB || 0;
    if (savingsInterest > 0) {
        if (age >= 60) {
            section80TTB = Math.max(section80TTB, savingsInterest);
        }
        else {
            section80TTA = Math.max(section80TTA, savingsInterest);
        }
    }
    const allowed80TTA = age < 60 ? Math.min(section80TTA, 10000) : 0;
    const allowed80TTB = age >= 60 ? Math.min(section80TTB, 50000) : 0;
    const oldRegimeDeductions = regime === 'old'
        ? (section80C + nps80CCD1B + allowed80D + hra + homeLoanInterest + section80EEA + allowed80TTA + allowed80TTB + otherDeductions)
        : 0;
    const taxableIncome = Math.max(0, annualIncome - standardDeduction - nps80CCD2 - oldRegimeDeductions);
    return { standardDeduction, oldRegimeDeductions, taxableIncome, nps80CCD2, allowed80D };
}
/**
 * Compute full tax breakdown for a given annual income.
 */
export function computeTax(annualIncome, regime = 'new', deductions = {}, incomeSource = 'salary', fiscalYear = CURRENT_FY) {
    // Input guard: reject non-finite or negative income using local variable
    let safeIncome = annualIncome;
    if (!Number.isFinite(safeIncome) || safeIncome < 0) {
        console.warn(`[TaxEngine] Invalid annualIncome: ${safeIncome}. Treating as 0.`);
        safeIncome = 0;
    }
    let safeRegime = (regime === 'new' || regime === 'old') ? regime : 'new';
    const slabs = getRegimeSlabs(safeRegime, fiscalYear);
    const { standardDeduction, oldRegimeDeductions, taxableIncome, nps80CCD2, allowed80D } = calculateTaxableIncome(safeIncome, safeRegime, deductions, incomeSource);
    let taxBeforeCess = calculateFromSlabs(taxableIncome, slabs);
    let rebateApplied = false;
    let marginalReliefApplied = false;
    let marginalReliefAmount87A = 0;
    const rebateLimit = safeRegime === 'new' ? 1200000 : 500000;
    if (taxableIncome <= rebateLimit) {
        taxBeforeCess = 0;
        rebateApplied = true;
    }
    else {
        // Marginal relief for 87A: tax cannot exceed the excess over rebate limit
        const excessOverLimit = taxableIncome - rebateLimit;
        if (taxBeforeCess > excessOverLimit) {
            marginalReliefAmount87A = taxBeforeCess - excessOverLimit;
            taxBeforeCess = excessOverLimit;
            marginalReliefApplied = true;
        }
    }
    const surcharge = computeSurcharge(taxBeforeCess, taxableIncome, safeRegime);
    const relief = computeMarginalRelief(taxBeforeCess, surcharge, taxableIncome, safeRegime, fiscalYear);
    const taxAfterSurcharge = taxBeforeCess + surcharge - relief;
    // 4% Health & Education Cess (applied on tax + surcharge)
    const cess = taxAfterSurcharge * CESS_RATE;
    const taxAmount = taxAfterSurcharge + cess;
    const effectiveRate = annualIncome > 0
        ? parseFloat(((taxAmount / annualIncome) * 100).toFixed(2))
        : 0;
    return {
        taxAmount: Math.round(taxAmount),
        effectiveRate,
        regime: safeRegime,
        rebateApplied,
        marginalReliefApplied: marginalReliefApplied || relief > 0,
        marginalReliefAmount: Math.round(relief + marginalReliefAmount87A),
        surchargeApplied: surcharge > 0,
        surchargeAmount: Math.round(surcharge),
        cess: Math.round(cess),
        taxBeforeCess: Math.round(taxBeforeCess),
        taxableIncome,
        annualIncome: safeIncome,
        standardDeduction,
        oldRegimeDeductions,
        nps80CCD2,
        allowed80D,
        fiscalYear,
    };
}
/**
 * Compute tax with deductions (convenience wrapper/alias).
 */
export function computeTaxWithDeductions(annualIncome, regime, deductions = {}, incomeSource = 'salary', fiscalYear = CURRENT_FY) {
    return computeTax(annualIncome, regime, deductions, incomeSource, fiscalYear);
}
/**
 * Get the marginal (highest applicable) tax slab percentage.
 */
export function getTaxSlab(annualIncome, regime = 'new', deductions = {}, incomeSource = 'salary', fiscalYear = CURRENT_FY) {
    // Input guard
    let safeIncome = annualIncome;
    if (!Number.isFinite(safeIncome) || safeIncome < 0)
        safeIncome = 0;
    let safeRegime = (regime === 'new' || regime === 'old') ? regime : 'new';
    const { taxableIncome } = calculateTaxableIncome(safeIncome, safeRegime, deductions, incomeSource);
    const slabs = getRegimeSlabs(safeRegime, fiscalYear);
    let marginalRate = 0;
    for (const slab of slabs) {
        if (taxableIncome > slab.min) {
            marginalRate = slab.rate;
        }
    }
    return marginalRate;
}
/**
 * Compare both regimes and return the better one.
 */
export function compareTaxRegimes(annualIncome, deductions = {}, incomeSource = 'salary', fiscalYear = CURRENT_FY) {
    // Input guard
    let safeIncome = annualIncome;
    if (!Number.isFinite(safeIncome) || safeIncome < 0)
        safeIncome = 0;
    const newRegime = computeTax(safeIncome, 'new', deductions, incomeSource, fiscalYear);
    const oldRegime = computeTax(safeIncome, 'old', deductions, incomeSource, fiscalYear);
    const recommended = newRegime.taxAmount <= oldRegime.taxAmount ? 'new' : 'old';
    return { newRegime, oldRegime, recommended };
}
/**
 * Get the effective marginal tax rate (slab + surcharge + cess) for a given income level.
 * Useful for post-tax drag adjustments on future returns.
 */
export function getEffectiveMarginalRate(annualIncome, regime = 'new', deductions = {}, incomeSource = 'salary', fiscalYear = CURRENT_FY) {
    const delta = 10000;
    const highIncome = annualIncome + delta;
    const lowIncome = Math.max(0, annualIncome - delta);
    const highRes = computeTax(highIncome, regime, deductions, incomeSource, fiscalYear);
    const lowRes = computeTax(lowIncome, regime, deductions, incomeSource, fiscalYear);
    const deltaIncome = highIncome - lowIncome;
    if (deltaIncome <= 0)
        return 0;
    const deltaTax = highRes.taxAmount - lowRes.taxAmount;
    const effectiveMarginal = deltaTax / deltaIncome;
    return parseFloat(Math.max(0, Math.min(effectiveMarginal, 0.45)).toFixed(4));
}

/**
 * WealthGenie XIRR Calculator — Newton-Raphson Implementation
 */
/**
 * Compute NPV (Net Present Value) for a given rate.
 */
function npv(rate, cashflows) {
    const d0 = cashflows[0].date.getTime();
    let total = 0;
    for (let i = 0; i < cashflows.length; i++) {
        const daysDiff = (cashflows[i].date.getTime() - d0) / 86400000; // ms → days
        const exponent = daysDiff / 365.25;
        total += cashflows[i].amount / Math.pow(1 + rate, exponent);
    }
    return total;
}
/**
 * Compute derivative of NPV with respect to rate (for Newton-Raphson).
 */
function npvDerivative(rate, cashflows) {
    const d0 = cashflows[0].date.getTime();
    let total = 0;
    for (let i = 0; i < cashflows.length; i++) {
        const daysDiff = (cashflows[i].date.getTime() - d0) / 86400000;
        const exponent = daysDiff / 365.25;
        total -= exponent * cashflows[i].amount / Math.pow(1 + rate, exponent + 1);
    }
    return total;
}
/**
 * Brent's method solver as fallback for robust root finding.
 */
function brentSolve(low, high, cashflows, tolerance = 1e-10, maxIter = 100) {
    let a = low;
    let b = high;
    let fa = npv(a, cashflows);
    let fb = npv(b, cashflows);
    if (fa === 0) {
        return { rate: a, converged: true, iterations: 0 };
    }
    if (fb === 0) {
        return { rate: b, converged: true, iterations: 0 };
    }
    if (fa * fb > 0) {
        return null;
    }
    let c = a;
    let fc = fa;
    let d = b - a;
    let e = d;
    for (let iter = 0; iter < maxIter; iter++) {
        if (fb === 0 || Math.abs(b - a) < tolerance) {
            return { rate: b, converged: true, iterations: iter };
        }
        if (fa * fb > 0) {
            a = c;
            fa = fc;
            d = b - a;
            e = d;
        }
        if (Math.abs(fa) < Math.abs(fb)) {
            c = b;
            b = a;
            a = c;
            fc = fb;
            fb = fa;
            fa = fc;
        }
        const tol = 2 * 2.220446049250313e-16 * Math.abs(b) + tolerance / 2;
        const m = (a - b) / 2;
        if (Math.abs(m) <= tol || fb === 0) {
            return { rate: b, converged: true, iterations: iter };
        }
        if (Math.abs(e) >= tol && Math.abs(fa) > Math.abs(fb)) {
            const s = fb / fa;
            let p, q;
            if (a === c) {
                p = 2 * m * s;
                q = 1 - s;
            }
            else {
                const r = fa / fc;
                const t = fb / fc;
                p = s * (2 * m * r * (r - t) - (b - a) * (t - 1));
                q = (r - 1) * (t - 1) * (s - 1);
            }
            if (p > 0) {
                q = -q;
            }
            else {
                p = -p;
            }
            if (2 * p < Math.min(3 * m * q - Math.abs(tol * q), Math.abs(e * q))) {
                e = d;
                d = p / q;
            }
            else {
                d = m;
                e = d;
            }
        }
        else {
            d = m;
            e = d;
        }
        c = b;
        fc = fb;
        if (Math.abs(d) > tol) {
            b += d;
        }
        else {
            b += m > 0 ? tol : -tol;
        }
        fb = npv(b, cashflows);
    }
    return { rate: b, converged: false, iterations: maxIter };
}
/**
 * Compute XIRR using Newton-Raphson iteration.
 */
export function computeXIRR(cashflows, guess = 0.1, tolerance = 1e-10, maxIterations = 100) {
    if (!Array.isArray(cashflows) || cashflows.length < 2) {
        return { rate: 0, converged: false, iterations: 0, npvResidual: NaN, error: 'Need at least 2 cashflows', annualizedReturn: '0.00%' };
    }
    let safeGuess = Number.isFinite(Number(guess)) ? Number(guess) : 0.1;
    safeGuess = Math.max(-0.99, Math.min(safeGuess, 50.0));
    // Normalize dates to UTC midnight and aggregate cashflows on the same date
    const dateGroups = new Map();
    for (const cf of cashflows) {
        const d = cf.date instanceof Date ? cf.date : new Date(cf.date);
        if (!Number.isFinite(d.getTime())) {
            return {
                rate: 0,
                converged: false,
                iterations: 0,
                npvResidual: NaN,
                error: `Invalid cashflow date: ${cf.date}`,
                annualizedReturn: '0.00%',
            };
        }
        const utcTime = Date.UTC(d.getUTCFullYear(), d.getUTCMonth(), d.getUTCDate());
        const amount = Number(cf.amount);
        if (Number.isFinite(amount) && Number.isFinite(utcTime)) {
            dateGroups.set(utcTime, (dateGroups.get(utcTime) || 0) + amount);
        }
    }
    const normalized = Array.from(dateGroups.entries()).map(([time, amount]) => ({
        amount,
        date: new Date(time),
    }));
    // Validate: at least one positive and one negative cashflow
    const hasPositive = normalized.some(cf => cf.amount > 0);
    const hasNegative = normalized.some(cf => cf.amount < 0);
    if (!hasPositive || !hasNegative) {
        return { rate: 0, converged: false, iterations: 0, npvResidual: NaN, error: 'Need both positive and negative cashflows', annualizedReturn: '0.00%' };
    }
    // Sort by date (ascending)
    normalized.sort((a, b) => a.date.getTime() - b.date.getTime());
    // Search bounds for bracket finding
    let lowRate = -0.99;
    let highRate = 50.0;
    let foundBracket = false;
    const gridSteps = 400;
    const gridMin = -0.99;
    const gridMax = 50.0;
    const gridRange = gridMax - gridMin;
    let prevR = gridMin;
    let prevV = npv(prevR, normalized);
    for (let step = 1; step <= gridSteps; step++) {
        const r = gridMin + (gridRange / gridSteps) * step;
        const v = npv(r, normalized);
        if (prevV * v < 0) {
            lowRate = prevR;
            highRate = r;
            foundBracket = true;
            break;
        }
        prevR = r;
        prevV = v;
    }
    const cashflowScale = normalized.reduce((sum, cf) => sum + Math.abs(cf.amount), 0);
    const npvTolerance = Math.max(cashflowScale * 1e-9, 1e-6);
    let rate = safeGuess;
    let iterations = 0;
    let converged = false;
    // PHASE 1: If we have a bracket, use bisection to narrow it to a tight interval first
    if (foundBracket) {
        let lo = lowRate, hi = highRate;
        for (let i = 0; i < 100; i++) {
            iterations++;
            const mid = (lo + hi) / 2;
            const valMid = npv(mid, normalized);
            if (Math.abs(valMid) < npvTolerance || (hi - lo) < tolerance) {
                rate = mid;
                converged = true;
                break;
            }
            if (npv(lo, normalized) * valMid < 0) {
                hi = mid;
            }
            else {
                lo = mid;
            }
        }
        if (!converged) {
            rate = (lo + hi) / 2;
            lowRate = lo;
            highRate = hi;
        }
    }
    // PHASE 2: Polish with Newton-Raphson (if not already converged)
    if (!converged) {
        for (let i = 0; i < maxIterations; i++) {
            iterations++;
            const val = npv(rate, normalized);
            if (Math.abs(val) < npvTolerance) {
                converged = true;
                break;
            }
            const deriv = npvDerivative(rate, normalized);
            let nextRate;
            if (Math.abs(deriv) > 1e-12) {
                nextRate = rate - val / deriv;
            }
            else {
                nextRate = foundBracket ? (lowRate + highRate) / 2 : rate + 0.05;
            }
            nextRate = Math.max(-0.99, Math.min(nextRate, 50.0));
            if (foundBracket && (nextRate <= lowRate || nextRate >= highRate)) {
                nextRate = (lowRate + highRate) / 2;
            }
            if (foundBracket) {
                const valNext = npv(nextRate, normalized);
                const valLow = npv(lowRate, normalized);
                if (valNext * valLow < 0) {
                    highRate = nextRate;
                }
                else {
                    lowRate = nextRate;
                }
            }
            if (Math.abs(nextRate - rate) < tolerance && Math.abs(npv(nextRate, normalized)) < npvTolerance) {
                rate = nextRate;
                converged = true;
                break;
            }
            rate = nextRate;
        }
    }
    // PHASE 3: Brent's Method fallback
    if (!converged && foundBracket) {
        const brentResult = brentSolve(lowRate, highRate, normalized, tolerance, maxIterations);
        if (brentResult) {
            rate = brentResult.rate;
            iterations += brentResult.iterations;
            converged = brentResult.converged;
        }
    }
    const finalNpv = npv(rate, normalized);
    if (converged) {
        return {
            rate: parseFloat(rate.toFixed(8)),
            converged: true,
            iterations,
            npvResidual: parseFloat(finalNpv.toFixed(6)),
            annualizedReturn: `${(rate * 100).toFixed(2)}%`,
        };
    }
    return {
        rate: parseFloat(rate.toFixed(8)),
        converged: false,
        iterations,
        npvResidual: parseFloat(finalNpv.toFixed(6)),
        annualizedReturn: `${(rate * 100).toFixed(2)}%`,
        warning: 'Newton-Raphson did not converge within max iterations',
    };
}
function addMonthsClamp(date, months) {
    const d = new Date(date.getTime());
    const expectedMonth = (d.getMonth() + months) % 12;
    d.setMonth(d.getMonth() + months);
    if (d.getMonth() !== expectedMonth) {
        d.setDate(0); // set to last day of expected month
    }
    return d;
}
/**
 * Compute XIRR for a SIP investment.
 */
export function computeSIPXIRR(monthlySIP, months, currentValue, startDate) {
    if (!Number.isFinite(monthlySIP) || monthlySIP <= 0)
        return { rate: 0, converged: false, iterations: 0, npvResidual: NaN, error: 'Invalid SIP amount', annualizedReturn: '0.00%' };
    if (!Number.isFinite(months) || months < 1)
        return { rate: 0, converged: false, iterations: 0, npvResidual: NaN, error: 'Invalid months', annualizedReturn: '0.00%' };
    if (!Number.isFinite(currentValue) || currentValue <= 0)
        return { rate: 0, converged: false, iterations: 0, npvResidual: NaN, error: 'Invalid current value', annualizedReturn: '0.00%' };
    const now = new Date();
    let start = startDate;
    if (!start) {
        start = new Date(now.getTime());
        start.setMonth(start.getMonth() - months);
    }
    const cashflows = [];
    for (let i = 0; i < months; i++) {
        const date = addMonthsClamp(start, i);
        cashflows.push({ amount: -monthlySIP, date });
    }
    cashflows.push({ amount: currentValue, date: now });
    return computeXIRR(cashflows);
}
